functions.renderPhysioPlan:
function renderPhysioPlan(out) {
  var r = document.getElementById('physio-result');
  var catColor = {
    'Electrotherapy':'#4f46e5','Thermotherapy':'#c0392b','Mechanotherapy':'#0369a1',
    'Phototherapy':'#b45309','Manual Therapy':'#064E3B','Exercise Therapy':'#0f766e','Taping':'#7c3aed'
  };
  var catBg = {
    'Electrotherapy':'#eef2ff','Thermotherapy':'#fef2f2','Mechanotherapy':'#dbeafe',
    'Phototherapy':'#fff7ed','Manual Therapy':'#d1fae5','Exercise Therapy':'#ccfbf1','Taping':'#ede9fe'
  };
  var html = '';

  // Header
  html += '<div style="background:linear-gradient(135deg,#0f766e,#042f2e);border-radius:11px;padding:14px 16px;margin-bottom:14px;color:#fff">'
    + '<div style="font-size:15px;font-weight:700">⚡ '+(out.title||'Physiotherapy Treatment Plan')+'</div>'
    + (out.diagnosis?'<div style="font-size:12px;opacity:.75;margin-top:3px">'+out.diagnosis+'</div>':'')
    + (out.clinicalRationale?'<div style="font-size:12px;opacity:.9;margin-top:7px;line-height:1.55;border-top:1px solid rgba(255,255,255,.2);padding-top:7px">'+out.clinicalRationale+'</div>':'')
    + '</div>';

  // Assessment
  if (out.assessment) {
    var a = out.assessment;
    html += '<div style="background:#f0fdf9;border:1px solid #5eead4;border-radius:10px;padding:12px 14px;margin-bottom:12px">'
      + '<div style="font-size:11px;font-weight:700;color:#0f766e;text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px">🔍 Clinical Assessment</div>';
    if (a.postureObservation) html += '<div style="font-size:12px;color:var(--tx);margin-bottom:6px"><b>Posture / Observation:</b> '+a.postureObservation+'</div>';
    if (a.specialTests && a.specialTests.length) {
      html += '<div style="font-size:11px;font-weight:700;color:#0f766e;margin-bottom:4px">Special Tests</div>';
      html += '<div style="display:flex;flex-wrap:wrap;gap:5px;margin-bottom:6px">';
      a.specialTests.forEach(function(t){html+='<span style="background:#ccfbf1;color:#0f766e;font-size:11px;padding:2px 8px;border-radius:10px">'+t+'</span>';});
      html += '</div>';
    }
    if (a.functionalLimitations && a.functionalLimitations.length) {
      html += '<div style="font-size:11px;font-weight:700;color:#0f766e;margin-bottom:4px">Functional Limitations</div>';
      a.functionalLimitations.forEach(function(fl){html+='<div style="font-size:12px;color:var(--tx);padding:2px 0">• '+fl+'</div>';});
    }
    html += '</div>';
  }

  // Modalities
  if (out.modalities && out.modalities.length) {
    html += '<div style="font-size:11px;font-weight:700;color:#0f766e;text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px">⚡ Treatment Modalities</div>';
    html += '<div style="display:flex;flex-direction:column;gap:10px;margin-bottom:14px">';
    out.modalities.forEach(function(m) {
      var cc = catColor[m.category]||'#0f766e';
      var cb = catBg[m.category]||'#ccfbf1';
      var p = m.parameters || {};
      html += '<div style="background:var(--surf);border:1.5px solid '+cc+'30;border-radius:11px;overflow:hidden">'
        + '<div style="background:'+cc+';color:#fff;padding:9px 14px;display:flex;align-items:center;justify-content:space-between">'
        + '<div><div style="font-size:13px;font-weight:700">'+m.name+'</div>'
        + (m.indication?'<div style="font-size:11px;opacity:.85">'+m.indication+'</div>':'')+'</div>'
        + '<span style="background:rgba(255,255,255,.25);padding:2px 9px;border-radius:10px;font-size:10px;font-weight:700;white-space:nowrap">'+m.category+'</span></div>'
        + '<div style="padding:11px 14px">'
        // Parameters grid
        + '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(130px,1fr));gap:6px;margin-bottom:10px">';
      if (p.frequency)    html += '<div style="background:'+cb+';border-radius:7px;padding:5px 8px"><div style="font-size:9px;font-weight:700;color:'+cc+';text-transform:uppercase">Frequency</div><div style="font-size:11px;color:var(--tx)">'+p.frequency+'</div></div>';
      if (p.intensity)    html += '<div style="background:'+cb+';border-radius:7px;padding:5px 8px"><div style="font-size:9px;font-weight:700;color:'+cc+';text-transform:uppercase">Intensity</div><div style="font-size:11px;color:var(--tx)">'+p.intensity+'</div></div>';
      if (p.duration)     html += '<div style="background:'+cb+';border-radius:7px;padding:5px 8px"><div style="font-size:9px;font-weight:700;color:'+cc+';text-transform:uppercase">Duration</div><div style="font-size:11px;color:var(--tx)">'+p.duration+'</div></div>';
      if (p.pulseWidth)   html += '<div style="background:'+cb+';border-radius:7px;padding:5px 8px"><div style="font-size:9px;font-weight:700;color:'+cc+';text-transform:uppercase">Pulse Width</div><div style="font-size:11px;color:var(--tx)">'+p.pulseWidth+'</div></div>';
      if (p.mode)         html += '<div style="background:'+cb+';border-radius:7px;padding:5px 8px"><div style="font-size:9px;font-weight:700;color:'+cc+';text-transform:uppercase">Mode</div><div style="font-size:11px;color:var(--tx)">'+p.mode+'</div></div>';
      if (p.temperature)  html += '<div style="background:'+cb+';border-radius:7px;padding:5px 8px"><div style="font-size:9px;font-weight:700;color:'+cc+';text-transform:uppercase">Temperature</div><div style="font-size:11px;color:var(--tx)">'+p.temperature+'</div></div>';
      html += '</div>';
      // Sessions
      html += '<div style="display:flex;gap:10px;margin-bottom:8px">';
      if (m.sessionsPerWeek) html += '<div style="background:#f0fdf9;border:1px solid #5eead4;border-radius:7px;padding:4px 10px;font-size:11px;color:#0f766e"><b>📅 Sessions/week:</b> '+m.sessionsPerWeek+'</div>';
      if (m.totalSessions)   html += '<div style="background:#f0fdf9;border:1px solid #5eead4;border-radius:7px;padding:4px 10px;font-size:11px;color:#0f766e"><b>🔢 Total:</b> '+m.totalSessions+'</div>';
      html += '</div>';
      // Technique
      if (m.technique) html += '<div style="font-size:12px;color:var(--tx);line-height:1.6;margin-bottom:8px;white-space:pre-line">'+m.technique+'</div>';
      // Outcome
      if (m.expectedOutcome) html += '<div style="font-size:11px;background:#d1fae5;border-radius:6px;padding:4px 8px;color:#064E3B;margin-bottom:6px">🎯 '+m.expectedOutcome+'</div>';
      // Contraindications
      if (m.contraindications && m.contraindications.length) {
        html += '<div style="background:#fef2f2;border-radius:6px;padding:5px 9px">';
        m.contraindications.forEach(function(c){html+='<div style="font-size:11px;color:#991b1b">⚠️ '+c+'</div>';});
        html += '</div>';
      }
      html += '</div></div>';
    });
    html += '</div>';
  }

  // Exercise Protocol — Full Categorized
  if (out.exerciseProtocol) {
    var ep = out.exerciseProtocol;
    var phases = ['phase1','phase2','phase3','phase4'];
    var phaseColors  = ['#4f46e5','#0369a1','#0f766e','#064E3B'];
    var phaseBgs     = ['#eef2ff','#dbeafe','#ccfbf1','#d1fae5'];
    var phaseBorders = ['#a5b4fc','#93c5fd','#5eead4','#6ee7b7'];
    // category meta: [key, icon, label, headerBg, headerText, rowBg, rowBorder]
    var CATS = [
      ['rangeOfMotion','🔄','Range of Motion','#dbeafe','#1e40af','#eff6ff','#bfdbfe'],
      ['stretching','🧘','Stretching','#ede9fe','#5b21b6','#f5f3ff','#ddd6fe'],
      ['strengthening','💪','Strengthening','#d1fae5','#064E3B','#f0fdf4','#86efac'],
      ['neuromuscular','⚖️','Neuromuscular & Proprioception','#fed7aa','#9a3412','#fff7ed','#fdba74'],
      ['cardiovascular','🏃','Cardiovascular / Aerobic','#fce7f3','#831843','#fdf2f8','#f9a8d4'],
      ['plyometrics','⚡','Plyometrics','#fef9c3','#713f12','#fefce8','#fde047'],
      ['sportSpecific','🏅','Sport-Specific Drills','#ccfbf1','#042f2e','#f0fdfa','#5eead4']
    ];
    html += '<div style="margin-bottom:14px"><div style="font-size:12px;font-weight:700;color:#0f766e;text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px">🏋️ Phased Exercise Protocol</div>';
    phases.forEach(function(ph, i) {
      var pdata = ep[ph];
      if (!pdata) return;
      var pc=phaseColors[i], pbg=phaseBgs[i], pbd=phaseBorders[i];
      html += '<details open style="background:var(--surf);border:1.5px solid '+pbd+';border-radius:12px;overflow:hidden;margin-bottom:10px">'
        + '<summary style="background:linear-gradient(135deg,'+pc+','+pc+'cc);color:#fff;padding:10px 14px;cursor:pointer;list-style:none;display:flex;align-items:center;justify-content:space-between">'
        + '<div><div style="font-size:13px;font-weight:700">Phase '+(i+1)+': '+(pdata.name||'Phase '+(i+1))+'</div>'
        + (pdata.duration?'<div style="font-size:10px;opacity:.8;margin-top:1px">⏱ '+pdata.duration+'</div>':'')
        + '</div><span style="font-size:10px;opacity:.8">▼</span></summary>'
        + '<div style="padding:10px 12px">';
      if (pdata.goals && pdata.goals.length) {
        html += '<div style="background:'+pbg+';border:1px solid '+pbd+';border-radius:8px;padding:7px 10px;margin-bottom:9px">'
          + '<div style="font-size:10px;font-weight:700;color:'+pc+';text-transform:uppercase;margin-bottom:5px">🎯 Phase Goals</div>';
        pdata.goals.forEach(function(g){if(g&&g.trim())html+='<div style="font-size:11px;color:var(--tx);padding:2px 0">• '+g+'</div>';});
        html += '</div>';
      }
      CATS.forEach(function(cat) {
        var cKey=cat[0],cIcon=cat[1],cLabel=cat[2],cHBg=cat[3],cHClr=cat[4],cRBg=cat[5],cRBdr=cat[6];
        var items = pdata[cKey];
        if (!items||!items.length) return;
        var valid = items.filter(function(it){return it.name&&it.name.trim();});
        if (!valid.length) return;
        html += '<div style="margin-bottom:8px;border-radius:9px;overflow:hidden;border:1px solid '+cRBdr+'">'
          + '<div style="background:'+cHBg+';padding:6px 11px;font-size:10px;font-weight:700;color:'+cHClr+';text-transform:uppercase;letter-spacing:.05em">'+cIcon+' '+cLabel+'</div>';
        valid.forEach(function(ex, ei) {
          var isLast=ei===valid.length-1;
          html += '<div style="background:'+cRBg+';padding:8px 11px'+(isLast?'':';border-bottom:0.5px solid '+cRBdr)+'">';
          html += '<div style="font-size:12px;font-weight:700;color:var(--tx);margin-bottom:3px">'+ex.name+'</div>';
          if (ex.method) html += '<div style="font-size:11px;color:var(--mu);line-height:1.55;margin-bottom:4px">'+ex.method+'</div>';
          var chips=[];
          if (ex.sets)            chips.push(['Sets',ex.sets]);
          if (ex.reps)            chips.push(['Reps',ex.reps]);
          if (ex.hold)            chips.push(['Hold',ex.hold]);
          if (ex.duration)        chips.push(['Duration',ex.duration]);
          if (ex.resistance)      chips.push(['Resistance',ex.resistance]);
          if (ex.intensity)       chips.push(['Intensity',ex.intensity]);
          if (ex.frequency)       chips.push(['Frequency',ex.frequency]);
          if (ex.targetMuscle)    chips.push(['Target Muscle',ex.targetMuscle]);
          if (ex.targetJoint)     chips.push(['Joint',ex.targetJoint]);
          if (ex.progressionNote) chips.push(['Progression',ex.progressionNote]);
          if (ex.criterion)       chips.push(['Criterion',ex.criterion]);
          if (chips.length) {
            html += '<div style="display:flex;flex-wrap:wrap;gap:4px;margin-top:3px">';
            chips.forEach(function(ch){html+='<div style="background:#fff;border:1px solid '+cRBdr+';border-radius:20px;padding:2px 8px;font-size:10px;color:'+cHClr+'"><span style="opacity:.7">'+ch[0]+':</span> <b>'+ch[1]+'</b></div>';});
            html += '</div>';
          }
          html += '</div>';
        });
        html += '</div>';
      });
      if (pdata.precautions&&pdata.precautions.length) {
        var vp=pdata.precautions.filter(function(p){return p&&p.trim();});
        if (vp.length) {
          html += '<div style="background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;padding:7px 10px;margin-top:4px"><div style="font-size:10px;font-weight:700;color:#991b1b;text-transform:uppercase;margin-bottom:4px">⚠️ Phase Precautions</div>';
          vp.forEach(function(p){html+='<div style="font-size:11px;color:#7f1d1d;padding:2px 0">• '+p+'</div>';});
          html += '</div>';
        }
      }
      html += '</div></details>';
    });
    html += '</div>';
  }

  // Manual Therapy
  if (out.manualTherapy && out.manualTherapy.length) {
    html += '<div style="background:#d1fae5;border:1px solid #86efac;border-radius:9px;padding:11px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#064E3B;text-transform:uppercase;margin-bottom:6px">🤲 Manual Therapy Techniques</div>';
    out.manualTherapy.forEach(function(mt){html+='<div style="font-size:12px;color:#022c22;padding:3px 0;border-bottom:0.5px solid #6ee7b7">• '+mt+'</div>';});
    html += '</div>';
  }

  // Daily Session Plan
  if (out.dailySessionPlan && out.dailySessionPlan.length) {
    html += '<div style="background:#f0fdf9;border:1px solid #5eead4;border-radius:9px;padding:11px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#0f766e;text-transform:uppercase;margin-bottom:7px">🕘 Daily Session Plan</div>';
    out.dailySessionPlan.forEach(function(dp){
      html+='<div style="display:flex;gap:10px;padding:4px 0;border-bottom:0.5px solid #5eead4;font-size:12px"><span style="color:#0f766e;font-weight:700;min-width:70px">'+dp.time+'</span><span style="color:var(--tx)">'+dp.activity+'</span></div>';
    });
    html += '</div>';
  }

  // Home Programme
  if (out.homeProgramme && out.homeProgramme.length) {
    html += '<div style="background:#ccfbf1;border:1px solid #5eead4;border-radius:9px;padding:11px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#0f766e;text-transform:uppercase;margin-bottom:6px">🏠 Home Programme</div>';
    out.homeProgramme.forEach(function(h){html+='<div style="font-size:12px;color:#042f2e;padding:3px 0;border-bottom:0.5px solid #99f6e4">• '+h+'</div>';});
    html += '</div>';
  }

  // Ergonomics & Posture
  if (out.ergonomicsPosture && out.ergonomicsPosture.length) {
    html += '<div style="background:#faf5ff;border:1px solid #d8b4fe;border-radius:9px;padding:11px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#7c3aed;text-transform:uppercase;margin-bottom:6px">🪑 Ergonomics & Posture</div>';
    out.ergonomicsPosture.forEach(function(e){html+='<div style="font-size:12px;color:#3b0764;padding:3px 0;border-bottom:0.5px solid #d8b4fe">• '+e+'</div>';});
    html += '</div>';
  }

  // Two-column: Progression + Patient Education
  html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">';
  if (out.progressionCriteria && out.progressionCriteria.length) {
    html += '<div style="background:#e0f2fe;border:1px solid #7dd3fc;border-radius:9px;padding:11px 14px">'
      + '<div style="font-size:11px;font-weight:700;color:#0369a1;text-transform:uppercase;margin-bottom:6px">📈 Progression Criteria</div>';
    out.progressionCriteria.forEach(function(c){html+='<div style="font-size:11px;color:#0c4a6e;padding:2px 0">• '+c+'</div>';});
    html += '</div>';
  }
  if (out.patientEducation && out.patientEducation.length) {
    html += '<div style="background:#fef9c3;border:1px solid #fde047;border-radius:9px;padding:11px 14px">'
      + '<div style="font-size:11px;font-weight:700;color:#713f12;text-transform:uppercase;margin-bottom:6px">📚 Patient Education</div>';
    out.patientEducation.forEach(function(e){html+='<div style="font-size:11px;color:#422006;padding:2px 0">• '+e+'</div>';});
    html += '</div>';
  }
  html += '</div>';

  // Red Flags
  if (out.redFlags && out.redFlags.length) {
    html += '<div style="background:#fef2f2;border:1px solid #fca5a5;border-left:3px solid #dc2626;border-radius:8px;padding:10px 13px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#991b1b;text-transform:uppercase;margin-bottom:5px">🚩 Red Flags — Refer Immediately</div>';
    out.redFlags.forEach(function(rf){html+='<div style="font-size:12px;color:#7f1d1d;padding:2px 0">• '+rf+'</div>';});
    html += '</div>';
  }

  // Expected Outcome
  if (out.expectedOutcome) {
    html += '<div style="background:#d1fae5;border:1px solid #6ee7b7;border-radius:9px;padding:11px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#064E3B;text-transform:uppercase;margin-bottom:5px">🎯 Overall Prognosis & Expected Outcome</div>'
      + '<div style="font-size:12px;color:#022c22;line-height:1.6">'+out.expectedOutcome+'</div></div>';
  }

  // Note
  if (out.note) html += '<div style="background:#fef2f2;border:1px solid #fca5a5;border-left:3px solid #dc2626;border-radius:8px;padding:10px 13px;font-size:11.5px;color:#7f1d1d;line-height:1.6;margin-bottom:10px"><strong>⚠️ Clinical Note:</strong> '+out.note+'</div>';

  // Signature
  if (out.signature) html += '<div style="margin-top:20px;padding-top:14px;border-top:1.5px solid rgba(15,118,110,.25);text-align:right;font-family:\'Cormorant Garamond\',serif;font-size:17px;font-weight:500;color:#0f766e;letter-spacing:.05em;padding-right:4px">'+out.signature+'</div>';

  html += '<button onclick="printChart(\'physio-result\')" class="diet-print-btn">🖨️ Print Physiotherapy Plan</button>';
  r.innerHTML = html;
  r.scrollIntoView({behavior:'smooth',block:'start'});
}
// ─── END PHYSIO PLANNER JS ───

var aiOpen = false;
let aiHistory = [];
let aiLoading = false;

const AI_SYSTEM = `You are an expert clinical AI assistant embedded in Dr. Vikranth's Complete Clinical Reference — a BNYS (Bachelor of Naturopathy and Yogic Sciences) clinical tool.

Clinical role: Support a Naturopathy and Yogic Sciences practice with evidence-based answers.
Guidelines:
- Ground responses in naturopathic principles, clinical nutrition, hydrotherapy, and therapeutic yoga.
- Factor in metabolic health and biochemical pathways when clinically relevant.
- Professional, clinical, and concise tone.
- Any routines or schedules: use specific times (6:00 AM, 10:00 AM, 12:30 PM).
- Never use the abbreviation "cd".
- When generating plans: sign off as Dr. Vikranth only (no preceding words).

Scope: naturopathy protocols, BNYS treatments, evidence-based medicine, pharmacology, lab interpretation, yoga therapy, hydrotherapy, clinical nutrition, differential diagnosis, and emergency medicine basics. Recommend specialist referral when appropriate. Keep answers concise and clinically precise.`;

functions.generatePhysioPlan:
async function generatePhysioPlan() {
  var result = document.getElementById('physio-result');
  var btn    = document.getElementById('physio-btn');
  var disease  = document.getElementById('physio-disease').value.trim();
  var age      = document.getElementById('physio-age').value;
  var stage    = document.getElementById('physio-stage').value;
  var region   = document.getElementById('physio-region').value;
  var setting  = document.getElementById('physio-setting').value;
  var pain     = document.getElementById('physio-pain').value;
  var goal     = document.getElementById('physio-goal').value;
  var contra   = document.getElementById('physio-contra').value;
  var modPref  = _physioSelectedModalities.length ? _physioSelectedModalities.join(', ') : 'all appropriate modalities';
  if (!disease) {
    result.innerHTML = '<div style="color:#c0392b;padding:9px 12px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">⚠️ Please enter a condition / diagnosis.</div>';
    return;
  }
  if (needsKey()) { needsKeyCheck('physio-result', 'Generate Physiotherapy Plan'); return; }
  if (!isOnline()) { showOfflineBanner('physio-result', 'Generate Physiotherapy Plan'); return; }
  btn.disabled = true; btn.textContent = 'Generating…';
  result.innerHTML = '<div style="text-align:center;padding:36px 20px;font-size:13px;color:#555"><div style="font-size:30px;animation:diet-spin 1.2s linear infinite;display:inline-block;margin-bottom:10px">⚡</div><br>Building physiotherapy plan for <b>'+disease+'</b>…<br><span style="font-size:11px;opacity:.6;margin-top:4px;display:block">Usually 15–20 seconds</span></div>';
  var sys = 'You are a senior BNYS-trained physiotherapist with 20 years of clinical experience in electrotherapy, manual therapy, and neuro-musculoskeletal rehabilitation. Respond ONLY with valid JSON (no markdown, no backticks, no explanations outside JSON).';
  var prompt = 'Condition: '+disease
    +'\nAge: '+(age||'adult')
    +'\nStage: '+stage
    +'\nBody region: '+region
    +'\nClinical setting: '+setting
    +'\nPain score: '+(pain||'moderate')
    +'/10\nPatient goal: '+goal
    +'\nPreferred modalities: '+modPref
    +(contra?'\nContraindications / precautions: '+contra:'')
    +'\n\nGenerate a comprehensive, evidence-based physiotherapy treatment plan. Include all relevant modalities with precise parameters. Never use "cd". Sign as Dr. Vikranth.'
    +'\n\nRespond ONLY with this exact JSON structure:'
    +'{"title":"Physiotherapy Treatment Plan — Dr. Vikranth",'
    +'"diagnosis":"full diagnosis with ICD description",'
    +'"clinicalRationale":"2-3 sentence evidence-based rationale for modality selection",'
    +'"assessment":{"postureObservation":"key postural findings to look for","specialTests":["test name: positive finding significance"],"functionalLimitations":["limitation"]},'
    +'"modalities":['
    +'{"name":"modality name e.g. TENS / IFT / Ultrasound / SWD / Laser / Wax Bath / Traction / Cryotherapy","category":"Electrotherapy|Thermotherapy|Mechanotherapy|Phototherapy|Manual Therapy|Exercise Therapy|Taping",'
    +'"indication":"why this modality for this condition",'
    +'"parameters":{"frequency":"e.g. 80 Hz / 4000 Hz carrier","intensity":"e.g. to sensory threshold / mA","duration":"e.g. 20 min","pulseWidth":"if applicable","mode":"e.g. continuous / burst / modulated","temperature":"if thermotherapy e.g. 40-44°C"},'
    +'"technique":"step-by-step application procedure",'
    +'"sessionsPerWeek":"e.g. 5 sessions / week",'
    +'"totalSessions":"e.g. 10–15 sessions",'
    +'"expectedOutcome":"measurable outcome",'
    +'"contraindications":["specific contraindication"]}'
    +'],'
    +'"exerciseProtocol":{'
    +'"phase1":{"name":"Acute / Pain Relief Phase","duration":"e.g. Week 1–2","goals":["specific goal for this phase"],'
    +'"rangeOfMotion":[{"name":"exercise name","method":"step-by-step technique","sets":"e.g. 2","reps":"e.g. 10","hold":"e.g. 5s","frequency":"e.g. 3x daily","targetJoint":"joint name"}],'
