    +'"cardiovascular":[{"name":"activity","method":"how to perform","intensity":"e.g. low / RPE 3-4","duration":"e.g. 10 min","frequency":"e.g. daily"}],'
    +'"precautions":["phase-specific precaution"]},'
    +'"phase2":{"name":"Mobility & Flexibility Phase","duration":"e.g. Week 3–4","goals":["specific goal"],'
    +'"rangeOfMotion":[{"name":"","method":"","sets":"","reps":"","hold":"","frequency":"","targetJoint":""}],'
    +'"stretching":[{"name":"","method":"","hold":"","reps":"","frequency":"","targetMuscle":""}],'
    +'"strengthening":[{"name":"","method":"","sets":"","reps":"","resistance":"","frequency":"","targetMuscle":""}],'
    +'"neuromuscular":[{"name":"","method":"","duration":"","sets":"","frequency":""}],'
    +'"cardiovascular":[{"name":"","method":"","intensity":"","duration":"","frequency":""}],'
    +'"precautions":["precaution"]},'
    +'"phase3":{"name":"Strengthening Phase","duration":"e.g. Week 5–8","goals":["specific goal"],'
    +'"rangeOfMotion":[{"name":"","method":"","sets":"","reps":"","hold":"","frequency":"","targetJoint":""}],'
    +'"stretching":[{"name":"","method":"","hold":"","reps":"","frequency":"","targetMuscle":""}],'
    +'"strengthening":[{"name":"","method":"","sets":"","reps":"","resistance":"","frequency":"","targetMuscle":""}],'
    +'"neuromuscular":[{"name":"","method":"","duration":"","sets":"","frequency":""}],'
    +'"cardiovascular":[{"name":"","method":"","intensity":"","duration":"","frequency":""}],'
    +'"plyometrics":[{"name":"exercise name","method":"technique","sets":"e.g. 3","reps":"e.g. 10","frequency":"e.g. 3x/week","progressionNote":"when to advance"}],'
    +'"precautions":["precaution"]},'
    +'"phase4":{"name":"Functional / Return to Activity","duration":"e.g. Week 9–12","goals":["specific goal"],'
    +'"rangeOfMotion":[{"name":"","method":"","sets":"","reps":"","hold":"","frequency":"","targetJoint":""}],'
    +'"stretching":[{"name":"","method":"","hold":"","reps":"","frequency":"","targetMuscle":""}],'
    +'"strengthening":[{"name":"","method":"","sets":"","reps":"","resistance":"","frequency":"","targetMuscle":""}],'
    +'"neuromuscular":[{"name":"","method":"","duration":"","sets":"","frequency":""}],'
    +'"cardiovascular":[{"name":"","method":"","intensity":"","duration":"","frequency":""}],'
    +'"plyometrics":[{"name":"","method":"","sets":"","reps":"","frequency":"","progressionNote":""}],'
    +'"sportSpecific":[{"name":"drill name","method":"technique description","sets":"","duration":"","frequency":"e.g. 3x/week","criterion":"return-to-sport criterion"}],'
    +'"precautions":["precaution"]}},'
    +'"manualTherapy":["Technique: procedure with grade/pressure/duration"],'
    +'"dailySessionPlan":[{"time":"e.g. 9:00 AM","activity":"specific modality or exercise"}],'
    +'"homeProgramme":["Home exercise or self-care instruction with sets/reps/frequency"],'
    +'"ergonomicsPosture":["Specific ergonomic advice for this condition"],'
    +'"progressionCriteria":["Criteria to progress to next phase"],'
    +'"redFlags":["Red flag symptom requiring medical referral"],'
    +'"patientEducation":["Key education point for patient"],'
    +'"expectedOutcome":"overall prognosis and timeline to recovery",'
    +'"note":"clinical safety disclaimer",'
    +'"signature":"Dr. Vikranth, BNYS"}';
  try {
    var raw = await callAI([{role:'system',content:sys},{role:'user',content:prompt}], 6000);
    var out = extractJSON(raw);
    if (!out) {
      result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">⚠️ Parse error — please try again.</div>';
      btn.disabled=false; btn.innerHTML='⚡ Generate Physiotherapy Treatment Plan'; return;
    }
    renderPhysioPlan(out);
  } catch(e) {
    result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">⚠️ '+(e.message||'Connection error')+' — check your API key and internet connection, then retry.</div>';
  }
  btn.disabled=false; btn.innerHTML='⚡ Generate Physiotherapy Treatment Plan';
}

functions.togglePhysioModality:
function togglePhysioModality(btn, mod) {
  var idx = _physioSelectedModalities.indexOf(mod);
  if (idx === -1) {
    _physioSelectedModalities.push(mod);
    btn.style.background='#ccfbf1'; btn.style.borderColor='#0f766e'; btn.style.color='#0f766e'; btn.style.fontWeight='700';
  } else {
    _physioSelectedModalities.splice(idx,1);
    btn.style.background=''; btn.style.borderColor=''; btn.style.color=''; btn.style.fontWeight='';
  }
}

functions.renderLabInterp:
function renderLabInterp(out) {
  var r = document.getElementById('labinterp-result');
  var riskColors = {Low:'#1a6b3c',Moderate:'#b45309',High:'#c0392b',Critical:'#7a0d0d'};
  var riskBg = {Low:'#e6f5ec',Moderate:'#fff7ed',High:'#fef2f2',Critical:'#fce4ec'};
  var stColors = {Optimal:'#1a6b3c',Normal:'#2d7a50',Borderline:'#b45309',Abnormal:'#c0392b',Critical:'#7a0d0d'};
  var stBg = {Optimal:'#e6f5ec',Normal:'#f0fdf4',Borderline:'#fff7ed',Abnormal:'#fef2f2',Critical:'#fce4ec'};
  var rc = riskColors[out.riskLevel]||'#555';
  var rb = riskBg[out.riskLevel]||'#f5f5f5';

  var html = '';

  // ── Header ──
  html += '<div style="background:linear-gradient(135deg,#1a6b3c,#0f4025);border-radius:13px;padding:16px 18px;margin-bottom:14px;color:#fff">'
    + '<div style="display:flex;align-items:center;gap:12px;margin-bottom:8px">'
    + '<div style="font-size:14px;font-weight:700;flex:1">&#128300; '+(out.title||'Lab Interpretation Report')+'</div>'
    + (out.riskLevel?'<div style="background:'+rb+';color:'+rc+';border:1.5px solid '+rc+'55;border-radius:20px;padding:3px 13px;font-size:11px;font-weight:800;white-space:nowrap">'+out.riskLevel+' Risk</div>':'')
    + '</div>'
    + (out.overallSummary?'<div style="font-size:12.5px;opacity:.9;line-height:1.7">'+out.overallSummary+'</div>':'')
    + '</div>';

  // ── Urgent flags ──
  if (out.urgentFlags && out.urgentFlags.length && out.urgentFlags[0].finding) {
    html += '<div style="background:#fce4ec;border:1.5px solid #ef9a9a;border-left:5px solid #c62828;border-radius:10px;padding:13px 15px;margin-bottom:14px">'
      + '<div style="font-size:11px;font-weight:800;color:#880e4f;text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px">&#128680; Urgent Flags — Require Immediate Attention</div>';
    out.urgentFlags.forEach(function(f){
      html += '<div style="background:#fff;border-radius:7px;padding:8px 11px;margin-bottom:6px">'
        + '<div style="font-size:12.5px;font-weight:700;color:#c62828">'+f.finding+'</div>'
        + (f.reason?'<div style="font-size:11.5px;color:#7f1d1d;margin-top:2px">'+f.reason+'</div>':'')
        + (f.action?'<div style="font-size:11.5px;color:#c62828;font-weight:600;margin-top:3px">&#8594; '+f.action+'</div>':'')
        + '</div>';
    });
    html += '</div>';
  }

  // ── Individual findings ──
  if (out.findings && out.findings.length) {
    html += '<div style="font-size:11px;font-weight:700;color:#1a6b3c;text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px">&#9707; Value-by-Value Interpretation</div>';
    html += '<div style="display:flex;flex-direction:column;gap:8px;margin-bottom:16px">';
    out.findings.forEach(function(f) {
      var sc = stColors[f.status]||'#555';
      var sb = stBg[f.status]||'#f5f5f5';
      html += '<div style="background:var(--surf);border:1.5px solid var(--bdr);border-radius:11px;overflow:hidden">'
        // Row 1: test name + value + ranges + status
        + '<div style="display:flex;align-items:center;gap:8px;padding:10px 14px;border-bottom:1px solid var(--bdr);flex-wrap:wrap">'
        + '<div style="font-size:13px;font-weight:700;color:var(--tx);flex:1;min-width:120px">'+f.test+'</div>'
        + '<div style="font-size:14px;font-weight:800;font-family:monospace;color:'+sc+'">'+f.value+'</div>'
        + (f.conventionalRange?'<div style="font-size:10.5px;color:var(--mu);background:var(--bg);border-radius:5px;padding:2px 7px">Ref: '+f.conventionalRange+'</div>':'')
        + (f.functionalRange?'<div style="font-size:10.5px;color:#0369a1;background:#e0f2fe;border-radius:5px;padding:2px 7px">Optimal: '+f.functionalRange+'</div>':'')
        + '<span style="background:'+sb+';color:'+sc+';border:1.5px solid '+sc+'44;border-radius:12px;padding:2px 10px;font-size:10.5px;font-weight:800">'+f.status+'</span>'
        + '</div>'
        // Row 2: clinical significance + naturopathic note
        + '<div style="padding:10px 14px;display:grid;grid-template-columns:1fr 1fr;gap:10px">'
        + '<div>'
        + '<div style="font-size:11.5px;color:var(--tx);line-height:1.6">'+f.clinicalSignificance+'</div>'
        + (f.linkedConditions && f.linkedConditions.length?'<div style="margin-top:5px;display:flex;flex-wrap:wrap;gap:4px">'+f.linkedConditions.map(function(c){return '<span style="background:#f1f5f9;border-radius:5px;padding:1px 7px;font-size:10px;color:#475569">'+c+'</span>';}).join('')+'</div>':'')
        + (f.nutrientLink?'<div style="margin-top:5px;font-size:11px;color:#7c3aed;background:#ede9fe;border-radius:6px;padding:4px 8px">&#9674; '+f.nutrientLink+'</div>':'')
        + (f.medicationEffect?'<div style="margin-top:4px;font-size:11px;color:#0369a1;background:#e0f2fe;border-radius:6px;padding:4px 8px">&#128138; '+f.medicationEffect+'</div>':'')
        + '</div>'
        + '<div style="background:#f0fdf4;border-radius:8px;padding:8px 10px">'
        + '<div style="font-size:10px;font-weight:700;color:#1a6b3c;text-transform:uppercase;margin-bottom:4px">&#127807; Naturopathic Note</div>'
        + '<div style="font-size:11.5px;color:#1a6b3c;line-height:1.6">'+f.naturopathicNote+'</div>'
        + (f.trend?'<div style="margin-top:5px;font-size:10.5px;color:#b45309;font-weight:600">&#8594; '+f.trend+'</div>':'')
        + '</div>'
        + '</div></div>';
    });
    html += '</div>';
  }

  // ── Pattern recognition ──
  if (out.patterns && out.patterns.length && out.patterns[0].name) {
    html += '<div style="background:#fef3c7;border:1.5px solid #fcd34d;border-radius:11px;padding:14px 16px;margin-bottom:14px">'
      + '<div style="font-size:11px;font-weight:700;color:#92400e;text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px">&#128270; Pattern Recognition</div>'
      + '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(250px,1fr));gap:9px">';
    out.patterns.forEach(function(p){
      html += '<div style="background:#fff;border-radius:8px;padding:10px 12px;border:1px solid #fcd34d">'
        + '<div style="font-size:12.5px;font-weight:700;color:#92400e">'+p.name+'</div>'
        + (p.values && p.values.length?'<div style="margin:4px 0;display:flex;flex-wrap:wrap;gap:3px">'+p.values.map(function(v){return '<span style="background:#fef3c7;border-radius:4px;padding:1px 6px;font-size:10px;color:#78350f;font-family:monospace">'+v+'</span>';}).join('')+'</div>':'')
        + (p.description?'<div style="font-size:11.5px;color:#78350f;line-height:1.5">'+p.description+'</div>':'')
        + '</div>';
    });
    html += '</div></div>';
  }

  // ── Nutrient deficiencies ──
  if (out.nutrientDeficiencies && out.nutrientDeficiencies.length && out.nutrientDeficiencies[0].nutrient) {
    html += '<div style="background:#ede9fe;border:1.5px solid #c4b5fd;border-radius:11px;padding:14px 16px;margin-bottom:14px">'
      + '<div style="font-size:11px;font-weight:700;color:#5b21b6;text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px">&#9674; Nutrient Deficiency Analysis</div>'
      + '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(230px,1fr));gap:9px">';
    var sevColor = {mild:'#b45309',moderate:'#c0392b',severe:'#7a0d0d'};
    out.nutrientDeficiencies.forEach(function(n){
      var sc2 = sevColor[n.severity]||'#5b21b6';
      html += '<div style="background:#fff;border-radius:8px;padding:10px 12px;border:1px solid #c4b5fd">'
        + '<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px">'
        + '<div style="font-size:12.5px;font-weight:700;color:#5b21b6;flex:1">'+n.nutrient+'</div>'
        + (n.severity?'<span style="background:'+sc2+'22;color:'+sc2+';border-radius:10px;padding:1px 8px;font-size:10px;font-weight:700;text-transform:capitalize">'+n.severity+'</span>':'')
        + '</div>'
        + (n.evidence?'<div style="font-size:11px;color:#4c1d95;margin-bottom:4px">Evidence: '+n.evidence+'</div>':'')
        + (n.supplement?'<div style="font-size:11.5px;color:#1a6b3c;background:#f0fdf4;border-radius:6px;padding:4px 8px;font-weight:600">&#128138; '+n.supplement+'</div>':'')
        + '</div>';
    });
    html += '</div></div>';
  }

  // ── Naturopathic Protocol ──
  if (out.naturoProtocol) {
    var np = out.naturoProtocol;
    html += '<div style="background:#e8f5e9;border:1.5px solid #a5d6a7;border-radius:11px;padding:14px 16px;margin-bottom:14px">'
      + '<div style="font-size:11px;font-weight:700;color:#1b5e20;text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px">&#127807; Naturopathic Management Protocol</div>';
    if (np.diet) html += '<div style="margin-bottom:7px;padding:8px 11px;background:#fff;border-radius:8px;border-left:3px solid #4caf50"><div style="font-size:10.5px;font-weight:700;color:#1a6b3c;margin-bottom:3px">DIET</div><div style="font-size:12px;color:#1b5e20;line-height:1.6">'+np.diet+'</div></div>';
    if (np.supplements && np.supplements.length) {
      html += '<div style="margin-bottom:7px;padding:8px 11px;background:#fff;border-radius:8px;border-left:3px solid #7c3aed"><div style="font-size:10.5px;font-weight:700;color:#5b21b6;margin-bottom:5px">SUPPLEMENTS</div>';
      html += '<div style="display:flex;flex-direction:column;gap:5px">';
      np.supplements.forEach(function(s){
        html += '<div style="display:grid;grid-template-columns:auto 1fr;gap:8px;align-items:start">'
          + '<div style="background:#ede9fe;border-radius:6px;padding:3px 9px;font-size:12px;font-weight:700;color:#5b21b6;white-space:nowrap">'+s.name+'</div>'
          + '<div style="font-size:11.5px;color:#4c1d95">'+(s.dose?'<span style="font-weight:600">'+s.dose+'</span>':'')+(s.rationale?' — '+s.rationale:'')+'</div>'
          + '</div>';
      });
      html += '</div></div>';
    }
    if (np.herbs) html += '<div style="margin-bottom:7px;padding:8px 11px;background:#fff;border-radius:8px;border-left:3px solid #b45309"><div style="font-size:10.5px;font-weight:700;color:#92400e;margin-bottom:3px">HERBS</div><div style="font-size:12px;color:#78350f;line-height:1.6">'+np.herbs+'</div></div>';
    if (np.lifestyle) html += '<div style="margin-bottom:7px;padding:8px 11px;background:#fff;border-radius:8px;border-left:3px solid #0369a1"><div style="font-size:10.5px;font-weight:700;color:#0369a1;margin-bottom:3px">LIFESTYLE</div><div style="font-size:12px;color:#0c4a6e;line-height:1.6">'+np.lifestyle+'</div></div>';
    if (np.hydrotherapy) html += '<div style="margin-bottom:7px;padding:8px 11px;background:#fff;border-radius:8px;border-left:3px solid #0891b2"><div style="font-size:10.5px;font-weight:700;color:#0891b2;margin-bottom:3px">HYDROTHERAPY</div><div style="font-size:12px;color:#164e63;line-height:1.6">'+np.hydrotherapy+'</div></div>';
    if (np.yoga) html += '<div style="margin-bottom:7px;padding:8px 11px;background:#fff;border-radius:8px;border-left:3px solid #be185d"><div style="font-size:10.5px;font-weight:700;color:#be185d;margin-bottom:3px">YOGA / PRANAYAMA</div><div style="font-size:12px;color:#881337;line-height:1.6">'+np.yoga+'</div></div>';
    if (np.avoidances) html += '<div style="padding:8px 11px;background:#fef2f2;border-radius:8px;border-left:3px solid #ef4444"><div style="font-size:10.5px;font-weight:700;color:#c0392b;margin-bottom:3px">AVOID</div><div style="font-size:12px;color:#7f1d1d;line-height:1.6">'+np.avoidances+'</div></div>';
    html += '</div>';
  }

  // ── Follow-up tests ──
  if (out.followUpTests && out.followUpTests.length && out.followUpTests[0].test) {
    html += '<div style="background:#e0f2fe;border:1.5px solid #7dd3fc;border-radius:11px;padding:14px 16px;margin-bottom:14px">'
      + '<div style="font-size:11px;font-weight:700;color:#0369a1;text-transform:uppercase;letter-spacing:.06em;margin-bottom:9px">&#128203; Recommended Follow-Up Tests</div>'
      + '<div style="display:flex;flex-direction:column;gap:6px">';
    out.followUpTests.forEach(function(t){
      html += '<div style="background:#fff;border-radius:8px;padding:8px 12px;display:grid;grid-template-columns:auto 1fr auto;gap:10px;align-items:center">'
        + '<div style="font-size:12.5px;font-weight:700;color:#0369a1">'+t.test+'</div>'
        + '<div style="font-size:11.5px;color:#0c4a6e">'+t.reason+'</div>'
        + (t.timing?'<div style="font-size:11px;color:#0369a1;background:#e0f2fe;border-radius:6px;padding:2px 8px;white-space:nowrap;font-weight:600">'+t.timing+'</div>':'')
        + '</div>';
    });
    html += '</div>';
    if (out.repeatTimeline) html += '<div style="margin-top:8px;font-size:12px;color:#0369a1;font-weight:600">&#8635; Repeat current panel: '+out.repeatTimeline+'</div>';
    html += '</div>';
  }

  // ── Referral advice ──
  if (out.referralAdvice) {
    html += '<div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:9px;padding:11px 14px;margin-bottom:12px;font-size:12px;color:#7c2d12;line-height:1.6"><strong>&#128203; Referral Advice:</strong> '+out.referralAdvice+'</div>';
  }

  // ── Patient explanation ──
  if (out.patientExplanation) {
    html += '<div style="background:#f0fdf4;border:1.5px solid #86efac;border-radius:11px;padding:14px 16px;margin-bottom:12px">'
      + '<div style="font-size:11px;font-weight:700;color:#1a6b3c;text-transform:uppercase;margin-bottom:6px">&#128172; Patient-Friendly Explanation</div>'
      + '<div style="font-size:13px;color:#14532d;line-height:1.8;font-style:italic">"'+out.patientExplanation+'"</div>'
      + '</div>';
  }

  // ── Disclaimer ──
  if (out.note) {
    html += '<div style="background:#fef2f2;border:1px solid #fca5a5;border-left:3px solid #dc2626;border-radius:8px;padding:10px 13px;font-size:11.5px;color:#7f1d1d;line-height:1.6;margin-bottom:12px"><strong>&#9888; Note:</strong> '+out.note+'</div>';
  }

  html += '<button onclick="printChart(\'labinterp-result\')" class="diet-print-btn">&#128424; Print Full Lab Report</button>';
  r.innerHTML = html;
  r.scrollIntoView({behavior:'smooth',block:'start'});
}

functions.generateLabInterp:
async function generateLabInterp() {
  var result = document.getElementById('labinterp-result');
  var btn    = document.getElementById('li-btn');
  var vals   = document.getElementById('li-input').value.trim();
  var age    = document.getElementById('li-age').value;
  var gen    = document.getElementById('li-gen').value;
  var mode   = document.getElementById('li-mode').value;
  var ctx    = document.getElementById('li-context').value;
  var meds   = document.getElementById('li-meds').value;
  var focus  = document.getElementById('li-focus').value;
  if (!vals || !age) {
    result.innerHTML = '<div style="color:#c0392b;padding:9px 12px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; Please enter lab values and patient age.</div>';
    return;
  }
  if (needsKey()) { needsKeyCheck('labinterp-result', 'Interpret Lab Results'); return; }
  if (!isOnline()) { showOfflineBanner('labinterp-result', 'Interpret Lab Results'); return; }
  btn.disabled = true; btn.textContent = 'Interpreting...';
  result.innerHTML = '<div style="text-align:center;padding:40px 20px;font-size:13px;color:#555"><div style="font-size:34px;animation:diet-spin 1.2s linear infinite;display:inline-block;margin-bottom:10px">&#128300;</div><br>Interpreting lab values...<br><span style="font-size:11px;opacity:.6;margin-top:4px;display:block">Usually 15-25 seconds</span></div>';

  var prompt = `You are an expert BNYS clinician, functional medicine doctor, and clinical biochemist. Provide a comprehensive, clinically rich lab interpretation.

Patient: ${age} year old ${gen}${ctx ? ', presenting with: ' + ctx : ''}${meds ? ', current medications: ' + meds : ''}.
Interpretation mode: ${mode}.
Report focus: ${focus}.

Lab values:
${vals}

Respond ONLY with valid JSON (no markdown, no backticks):
{
  "title": "Lab Interpretation Report — [patient age/gender/context]",
  "overallSummary": "3-4 sentence comprehensive clinical summary including key findings and overall health picture",
  "riskLevel": "Low|Moderate|High|Critical",
  "urgentFlags": [
    {"finding": "urgent finding", "reason": "why urgent", "action": "immediate action required"}
  ],
  "findings": [
    {
      "test": "test name",
      "value": "reported value with unit",
      "conventionalRange": "standard lab reference range",
      "functionalRange": "optimal functional medicine range",
      "status": "Optimal|Normal|Borderline|Abnormal|Critical",
      "trend": "consider monitoring|investigate|treat urgently|recheck in X weeks",
      "clinicalSignificance": "what this value means clinically in 2-3 sentences",
      "linkedConditions": ["condition this value is associated with"],
