functions.renderAcuPoints:
function renderAcuPoints(out) {
  var r = document.getElementById('acu-result');
  var html = '';

  // Header
  html += '<div style="background:linear-gradient(135deg,#b45309,#7c2d12);border-radius:12px;padding:16px 18px;margin-bottom:14px;color:#fff">'
    + '<div style="font-size:16px;font-weight:700">&#128070; '+(out.title||'Point Prescription')+'</div>'
    + (out.intro?'<div style="font-size:12.5px;opacity:.9;margin-top:5px;line-height:1.6">'+out.intro+'</div>':'')
    + '</div>';

  // TCM Diagnosis banner
  if (out.tcmPattern || out.principleOfTreatment) {
    html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px">'
      + (out.tcmPattern?'<div style="background:#fef3c7;border:1px solid #fcd34d;border-radius:9px;padding:10px 13px"><div style="font-size:10px;font-weight:700;color:#92400e;text-transform:uppercase;margin-bottom:3px">&#9674; TCM / Ayurvedic Pattern</div><div style="font-size:12.5px;color:#78350f;font-weight:600">'+out.tcmPattern+'</div></div>':'')
      + (out.principleOfTreatment?'<div style="background:#ede9fe;border:1px solid #c4b5fd;border-radius:9px;padding:10px 13px"><div style="font-size:10px;font-weight:700;color:#5b21b6;text-transform:uppercase;margin-bottom:3px">&#9670; Treatment Principle</div><div style="font-size:12.5px;color:#4c1d95;font-weight:600">'+out.principleOfTreatment+'</div></div>':'')
      + '</div>';
  }

  // Primary points
  if (out.primaryPoints && out.primaryPoints.length) {
    html += '<div style="font-size:11px;font-weight:700;color:#b45309;text-transform:uppercase;letter-spacing:.06em;margin-bottom:9px">&#128073; Primary Points ('+out.primaryPoints.length+')</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:10px;margin-bottom:16px">';
    out.primaryPoints.forEach(function(p) {
      html += '<div style="background:var(--surf);border:1.5px solid var(--bdr);border-radius:11px;overflow:hidden">'
        + '<div style="background:#b45309;color:#fff;padding:9px 13px">'
        + '<div style="display:flex;align-items:center;gap:8px">'
        + '<div style="background:rgba(255,255,255,.25);border-radius:6px;padding:3px 9px;font-size:14px;font-weight:800;font-family:monospace">'+(p.code||'')+'</div>'
        + '<div><div style="font-size:12.5px;font-weight:700">'+(p.name||'')+'</div>'
        + (p.meridian?'<div style="font-size:10.5px;opacity:.85">'+p.meridian+' meridian</div>':'')+'</div></div></div>'
        + '<div style="padding:10px 13px;display:flex;flex-direction:column;gap:4px">'
        + (p.location?'<div style="font-size:11.5px;background:#fff7ed;border-radius:5px;padding:4px 8px;color:#92400e"><b>&#128205; Location:</b> '+p.location+'</div>':'')
        + (p.acupressureMethod?'<div style="font-size:11.5px;padding:3px 0;border-bottom:0.5px solid var(--bdr)"><b>Acupressure:</b> '+p.acupressureMethod+'</div>':'')
        + (p.needleDepth?'<div style="font-size:11.5px;padding:3px 0;border-bottom:0.5px solid var(--bdr);color:#0369a1"><b>&#128314; Needle depth:</b> '+p.needleDepth+'</div>':'')
        + (p.stimulation?'<div style="font-size:11.5px;padding:3px 0;border-bottom:0.5px solid var(--bdr)"><b>Stimulation:</b> '+p.stimulation+'</div>':'')
        + (p.duration?'<div style="font-size:11.5px;padding:3px 0;border-bottom:0.5px solid var(--bdr)"><b>Duration:</b> '+p.duration+'</div>':'')
        + (p.benefit?'<div style="font-size:12px;color:#1a6b3c;line-height:1.4;margin-top:2px">&#127807; '+p.benefit+'</div>':'')
        + (p.caution?'<div style="font-size:11px;background:#fef2f2;border-radius:5px;padding:3px 7px;margin-top:4px;color:#c0392b">&#9888; '+p.caution+'</div>':'')
        +'</div></div>';
    });
    html += '</div>';
  }

  // Marma points
  if (out.marmaPoints && out.marmaPoints.length) {
    html += '<div style="font-size:11px;font-weight:700;color:#7c3aed;text-transform:uppercase;letter-spacing:.06em;margin-bottom:9px">&#9672; Marma Points ('+out.marmaPoints.length+')</div>';
    html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:8px;margin-bottom:16px">';
    out.marmaPoints.forEach(function(p) {
      html += '<div style="background:var(--surf);border:1.5px solid #ede9fe;border-radius:10px;overflow:hidden">'
        + '<div style="background:#7c3aed;color:#fff;padding:8px 12px;font-size:13px;font-weight:700">'+p.name+'</div>'
        + '<div style="padding:9px 12px">'
        + (p.location?'<div style="font-size:11.5px;color:#5b21b6;margin-bottom:4px">&#128205; '+p.location+'</div>':'')
        + (p.technique?'<div style="font-size:11.5px;padding:2px 0;border-bottom:0.5px solid #ede9fe"><b>Technique:</b> '+p.technique+'</div>':'')
        + (p.benefit?'<div style="font-size:12px;color:#1a6b3c;margin-top:4px">&#127807; '+p.benefit+'</div>':'')
        +'</div></div>';
    });
    html += '</div>';
  }

  // Ear acupuncture
  if (out.earAcupuncture && out.earAcupuncture.length) {
    html += '<div style="background:#e0f2fe;border:1px solid #7dd3fc;border-radius:10px;padding:12px 14px;margin-bottom:14px">'
      + '<div style="font-size:11px;font-weight:700;color:#0369a1;text-transform:uppercase;margin-bottom:8px">&#128066; Ear Acupuncture / Auriculotherapy Points</div>'
      + '<div style="display:flex;flex-wrap:wrap;gap:7px">';
    out.earAcupuncture.forEach(function(e) {
      html += '<div style="background:#fff;border:1px solid #7dd3fc;border-radius:8px;padding:6px 10px;min-width:130px">'
        + '<div style="font-size:12.5px;font-weight:700;color:#0369a1">'+e.point+'</div>'
        + (e.location?'<div style="font-size:11px;color:#0c4a6e">'+e.location+'</div>':'')
        + (e.indication?'<div style="font-size:11px;color:#075985;margin-top:2px">'+e.indication+'</div>':'')
        + '</div>';
    });
    html += '</div></div>';
  }

  // Session protocol
  if (out.sessionProtocol) {
    var sp = out.sessionProtocol;
    html += '<div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:10px;padding:13px 15px;margin-bottom:12px">'
      + '<div style="font-size:11px;font-weight:700;color:#c2410c;text-transform:uppercase;margin-bottom:8px">&#128336; Session Protocol</div>'
      + '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:6px">'
      + (sp.frequency?'<div style="font-size:12px;background:#fff;border-radius:7px;padding:6px 10px"><b>Frequency:</b><br><span style="color:#7c2d12">'+sp.frequency+'</span></div>':'')
      + (sp.totalSessions?'<div style="font-size:12px;background:#fff;border-radius:7px;padding:6px 10px"><b>Course length:</b><br><span style="color:#7c2d12">'+sp.totalSessions+'</span></div>':'')
      + (sp.duration?'<div style="font-size:12px;background:#fff;border-radius:7px;padding:6px 10px"><b>Session time:</b><br><span style="color:#7c2d12">'+sp.duration+'</span></div>':'')
      + (sp.pressure?'<div style="font-size:12px;background:#fff;border-radius:7px;padding:6px 10px"><b>Pressure level:</b><br><span style="color:#7c2d12">'+sp.pressure+'</span></div>':'')
      + (sp.timing?'<div style="font-size:12px;background:#fff;border-radius:7px;padding:6px 10px"><b>Best time:</b><br><span style="color:#7c2d12">'+sp.timing+'</span></div>':'')
      + (sp.sequence?'<div style="font-size:12px;background:#fff;border-radius:7px;padding:6px 10px;grid-column:1/-1"><b>Sequence:</b> <span style="color:#7c2d12">'+sp.sequence+'</span></div>':'')
      + '</div></div>';
  }

  // Lifestyle
  if (out.lifestyle && out.lifestyle.length) {
    html += '<div style="background:#f0fdf4;border:1px solid #86efac;border-radius:9px;padding:11px 14px;margin-bottom:11px">'
      + '<div style="font-size:11px;font-weight:700;color:#166534;text-transform:uppercase;margin-bottom:6px">&#127803; Supporting Lifestyle & Diet (TCM-based)</div>';
    out.lifestyle.forEach(function(s){html+='<div style="font-size:12px;color:#14532d;padding:2px 0">&#8226; '+s+'</div>';});
    html += '</div>';
  }

  // Self-care
  if (out.selfCareInstructions && out.selfCareInstructions.length) {
    html += '<div style="background:#e8f5e9;border:1px solid #a5d6a7;border-radius:9px;padding:11px 14px;margin-bottom:11px">'
      + '<div style="font-size:11px;font-weight:700;color:#1b5e20;text-transform:uppercase;margin-bottom:6px">&#127775; Self-Care (Patient Instructions)</div>';
    out.selfCareInstructions.forEach(function(s){html+='<div style="font-size:12px;color:#1b5e20;padding:2px 0">&#8226; '+s+'</div>';});
    html += '</div>';
  }

  // Contraindications
  if (out.contraindications && out.contraindications.length) {
    html += '<div style="background:#fce4ec;border:1px solid #f48fb1;border-radius:9px;padding:11px 14px;margin-bottom:11px">'
      + '<div style="font-size:11px;font-weight:700;color:#880e4f;text-transform:uppercase;margin-bottom:6px">&#9888; Contraindications</div>';
    out.contraindications.forEach(function(c2){html+='<div style="font-size:12px;color:#880e4f;padding:2px 0">&#8226; '+c2+'</div>';});
    html += '</div>';
  }

  // Disclaimer
  if (out.note){html+='<div style="background:#fef2f2;border:1px solid #fca5a5;border-left:3px solid #dc2626;border-radius:8px;padding:10px 13px;font-size:11.5px;color:#7f1d1d;line-height:1.6;margin-bottom:12px"><strong>&#9888; Note:</strong> '+out.note+'</div>';}

  html+='<button onclick="printChart(\'acu-result\')" class="diet-print-btn">&#128424; Print Point Prescription</button>';
  r.innerHTML=html;
  r.scrollIntoView({behavior:'smooth',block:'start'});
}

