functions.renderDietChart:
function renderDietChart(chart, disease, pref) {
  var result = document.getElementById('diet-result');

  // Slot icon map
  var slotIcons = {
    'warm water':    '&#128167;',
    'warm water + physical': '&#128167;',
    'morning drink': '&#127977;',
    'breakfast':     '&#127859;',
    'mid-morning':   '&#127822;',
    'lunch':         '&#127857;',
    'evening':       '&#9749;',
    'dinner':        '&#127769;',
    'night drink':   '&#127772;'
  };
  function slotIcon(time) {
    var t = (time||'').toLowerCase();
    for (var k in slotIcons) { if (t.includes(k)) return slotIcons[k]; }
    if (t.includes('warm water')) return '&#128167;';  // fallback for merged slot
    return '&#127807;';
  }

  // Slot type detection
  function isWaterSlot(slot) { return (slot.time||'').toLowerCase().includes('warm water'); }
  function isMorningDrink(slot) { return (slot.time||'').toLowerCase().includes('morning drink'); }

  // Slot background colours
  var slotColors = {
    'warm water':    '#e0f7fa',
    'morning drink': '#fff8e1',
    'breakfast':     '#fff3e0',
    'mid-morning':   '#fce4ec',
    'lunch':         '#e8f5e9',
    'evening':       '#ede7f6',
    'dinner':        '#e3f2fd',
    'night drink':   '#f3e5f5'
  };
  var slotBorders = {
    'warm water':    '#00acc1',
    'morning drink': '#f9a825',
    'breakfast':     '#fb8c00',
    'mid-morning':   '#e91e63',
    'lunch':         '#2e7d32',
    'evening':       '#7b1fa2',
    'dinner':        '#1565c0',
    'night drink':   '#6a1b9a'
  };
  function slotBg(time) {
    var t = (time||'').toLowerCase();
    for (var k in slotColors) { if (t.includes(k)) return [slotColors[k], slotBorders[k]]; }
    return ['#f5f5f5','#9e9e9e'];
  }

  // Header
  var today = new Date().toLocaleDateString('en-GB',{day:'numeric',month:'long',year:'numeric'});
  var html = '<div id="diet-print-header" style="display:none;border-bottom:2px solid #1e4a2e;padding-bottom:8px;margin-bottom:14px">'
    + '<div style="font-size:18px;font-weight:700;color:#1e4a2e">&#127807; Dr. Vikranth — Naturopathic Diet Plan</div>'
    + '<div style="font-size:12px;color:#555;margin-top:3px">Generated: ' + today + ' &nbsp;|&nbsp; Disease: ' + disease + ' &nbsp;|&nbsp; Diet: ' + pref + '</div>'
    + '</div>';
  html += '<div style="background:linear-gradient(135deg,#064E3B,#059669);border-radius:12px;padding:16px 18px;margin-bottom:16px;color:#d4edd8">'
    + '<div style="font-size:16px;font-weight:700;margin-bottom:4px">&#127807; ' + (chart.title||'Naturopathic Diet Plan') + '</div>'
    + '<div style="font-size:12px;opacity:.85;line-height:1.6">' + (chart.intro||'') + '</div>'
    + '</div>';

  // Slots — one-sheet layout
  html += '<div style="font-size:11.5px;font-weight:700;color:#064E3B;margin-bottom:10px;text-transform:uppercase;letter-spacing:.07em">&#128338; Daily Routine &amp; Meal Options</div>';
  html += '<div style="display:flex;flex-direction:column;gap:8px;margin-bottom:16px">';

  (chart.slots||[]).forEach(function(slot) {
    var sc = slotBg(slot.time);
    var bg = sc[0], bdr = sc[1];
    var icon = slotIcon(slot.time);
    var isWater    = (slot.time||'').toLowerCase().includes('warm water');
    var isActivity = (slot.time||'').toLowerCase().includes('physical');
    var headerBg   = isWater ? '#00838f' : isActivity ? '#2e7d32' : '#1e4a2e';

    var isWater  = isWaterSlot(slot);
    var isMDrink = isMorningDrink(slot);
    // Header colour per slot type
    var headerBgFinal = isWater ? '#00838f' : isMDrink ? '#e65100' : '#1e4a2e';

    html += '<div style="border-radius:10px;overflow:hidden;border:1.5px solid ' + bdr + ';margin-bottom:2px">';
    // Header
    html += '<div style="background:' + headerBgFinal + ';color:#fff;padding:9px 14px;display:flex;align-items:center;gap:8px;flex-wrap:wrap">'
      + '<span style="font-size:17px">' + icon + '</span>'
      + '<span style="font-size:13px;font-weight:700;flex:1">' + slot.time + '</span>'
      + '<span style="background:rgba(255,255,255,.22);font-size:10px;padding:2px 8px;border-radius:10px;font-weight:600">CONDITION-BASED</span>'
      + '</div>';
    // Options
    html += '<div style="background:' + bg + ';padding:10px 14px">';
    if (slot.options && slot.options.length) {
      html += '<div style="font-size:10.5px;font-weight:600;color:#555;margin-bottom:7px;text-transform:uppercase;letter-spacing:.05em">Choose any option:</div>';
      html += '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:5px">';
      slot.options.forEach(function(opt, oidx) {
        html += '<div style="background:#fff;border:1px solid ' + bdr + ';border-radius:7px;padding:7px 10px;font-size:12px;color:#333;display:flex;align-items:flex-start;gap:7px">'
          + '<span style="background:' + headerBgFinal + ';color:#fff;border-radius:50%;width:19px;height:19px;min-width:19px;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;margin-top:1px">' + (oidx+1) + '</span>'
          + '<span style="line-height:1.5">' + opt + '</span>'
          + '</div>';
      });
      html += '</div>';
    }
    html += '</div></div>';
  });
  html += '</div>';

  // Foods to eat more
  if (chart.eatMore && chart.eatMore.length) {
    html += '<div style="background:#e8f5e9;border:1px solid #a5d6a7;border-radius:9px;padding:12px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#1b5e20;text-transform:uppercase;letter-spacing:.05em;margin-bottom:8px">&#9989; Therapeutic Foods — Eat More</div>'
      + '<div style="display:flex;flex-wrap:wrap;gap:5px">';
    chart.eatMore.forEach(function(f) {
      html += '<span style="background:#fff;border:1px solid #66bb6a;border-radius:20px;padding:3px 10px;font-size:11.5px;color:#1b5e20;font-weight:500">' + f + '</span>';
    });
    html += '</div></div>';
  }

  // Foods to avoid
  if (chart.avoid && chart.avoid.length) {
    html += '<div style="background:#fce4ec;border:1px solid #f48fb1;border-radius:9px;padding:12px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#880e4f;text-transform:uppercase;letter-spacing:.05em;margin-bottom:8px">&#10060; Foods to Avoid</div>'
      + '<div style="display:flex;flex-wrap:wrap;gap:5px">';
    chart.avoid.forEach(function(f) {
      html += '<span style="background:#fff;border:1px solid #f48fb1;border-radius:20px;padding:3px 10px;font-size:11.5px;color:#880e4f;font-weight:500">' + f + '</span>';
    });
    html += '</div></div>';
  }

  // Herbs
  if (chart.herbs && chart.herbs.length) {
    html += '<div style="background:#fff8e1;border:1px solid #ffca28;border-radius:9px;padding:12px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#f57f17;text-transform:uppercase;letter-spacing:.05em;margin-bottom:6px">&#127807; Therapeutic Herbs &amp; Supplements</div>';
    chart.herbs.forEach(function(h) {
      html += '<div style="font-size:12px;padding:4px 0;border-bottom:0.5px solid #ffe082;color:#5a4200;line-height:1.5">&#8226; ' + h + '</div>';
    });
    html += '</div>';
  }

  // Weekly variation tips
  if (chart.weeklyTips && chart.weeklyTips.length) {
    html += '<div style="background:#e8eaf6;border:1px solid #9fa8da;border-radius:9px;padding:12px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#283593;text-transform:uppercase;letter-spacing:.05em;margin-bottom:6px">&#128197; Weekly Variation Tips</div>';
    chart.weeklyTips.forEach(function(t) {
      html += '<div style="font-size:12px;padding:4px 0;border-bottom:0.5px solid #c5cae9;color:#1a237e;line-height:1.5">&#8226; ' + t + '</div>';
    });
    html += '</div>';
  }

  // Lifestyle
  if (chart.lifestyle && chart.lifestyle.length) {
    html += '<div style="background:#e0f2f1;border:1px solid #80cbc4;border-radius:9px;padding:12px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#004d40;text-transform:uppercase;letter-spacing:.05em;margin-bottom:6px">&#129504; Lifestyle Recommendations</div>';
    chart.lifestyle.forEach(function(t) {
      html += '<div style="font-size:12px;padding:4px 0;border-bottom:0.5px solid #80cbc4;color:#00695c;line-height:1.5">&#8226; ' + t + '</div>';
    });
    html += '</div>';
  }

  // Clinical note
  if (chart.note) {
    html += '<div style="background:#fce4ec;border:1px solid #f48fb1;border-left:3px solid #c62828;border-radius:8px;padding:10px 13px;font-size:11.5px;color:#7f1d1d;line-height:1.6;margin-bottom:10px">'
      + '<strong>&#9888; Clinical Note:</strong> ' + chart.note + '</div>';
  }

  html += '<button class="diet-print-btn" onclick="printChart(\'diet-result\')">&#128424; Print / Save as PDF</button>';
  result.innerHTML = html;
  result.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

