async function generateDietChart() {
  var disease  = document.getElementById('diet-disease').value.trim();
  var age      = document.getElementById('diet-age').value.trim();
  var pref     = document.getElementById('diet-pref').value;
  var avoid    = document.getElementById('diet-avoid').value.trim();
  var wt       = document.getElementById('diet-wt').value.trim();
  var activity = document.getElementById('diet-activity').value;
  var duration = document.getElementById('diet-duration').value;
  var cooking  = document.getElementById('diet-cooking').value;
  var history  = document.getElementById('diet-history').value.trim();
  var result   = document.getElementById('diet-result');
  var btn      = document.getElementById('diet-btn');

  if (!disease) {
    result.innerHTML = '<div style="color:#c0392b;font-size:12px;padding:8px 12px;'
      + 'background:#fef2f2;border-radius:7px;border:1px solid #fca5a5">'
      + '&#9888; Please enter a disease or condition.</div>';
    return;
  }
  if (needsKeyCheck('diet-result', 'AI Diet Chart Generator')) return;
  if (!isOnline()) { showOfflineBanner('diet-result', 'AI Diet Chart Generator'); return; }

  if (btn) { btn.disabled = true; btn.textContent = 'Generating...'; }
  result.innerHTML = '<div style="text-align:center;padding:40px 20px;color:#7c3aed;font-size:13px">'
    + '<div style="display:inline-block;font-size:32px;animation:diet-spin 1.2s linear infinite;margin-bottom:10px">&#127807;</div>'
    + '<br>Building diet chart for <b>' + disease + '</b>...<br>'
    + '<span style="font-size:11px;opacity:.7;margin-top:4px;display:block">Usually 10-15 seconds</span></div>';

  var _sys = 'You are an expert clinical AI assistant supporting a Naturopathy and Yogic Sciences (BNYS) practice. Your primary responsibility is to generate structured, practical, and medically sound wellness and diet plans based on the patient symptoms, vitals, or diagnoses provided by the attending physician.\n\nClinical Guidelines:\n- Ground all recommendations in evidence-based naturopathic principles, clinical nutrition, hydrotherapy, and therapeutic yoga.\n- When relevant, factor in metabolic health and biochemical pathways (e.g., intracellular mineral balance such as magnesium and phosphate) to support deep cellular healing.\n- Maintain a highly professional, clinical, yet patient-friendly tone.\n\nStrict Formatting Rules:\n- All daily routines and diet plans MUST use specific times (e.g., 6:00 AM, 8:00 AM, 12:30 PM). Never group by broad categories alone.\n- NEVER use the abbreviation cd under any circumstances. Write all instructions clearly.\n- Every plan must end with the signature: Dr. Vikranth — the name only, no preceding words like Regards or Sincerely.\n\nRespond ONLY with valid JSON (no markdown, no backticks).';
  var prompt = 'Patient condition: ' + disease
    + '\nAge: ' + (age||'adult')
    + (wt ? '\nWeight: ' + wt + 'kg' : '')
    + '\nActivity level: ' + activity
    + '\nPlan duration: ' + duration
    + '\nCooking access: ' + cooking
    + '\nDietary preference: ' + pref
    + '\nFoods to avoid: ' + (avoid||'none')
    + (history ? '\nMedical history and comorbidities: ' + history : '')
    + '\n\nGenerate a complete time-structured naturopathic diet plan with EXACTLY 8 time slots. Factor in relevant biochemical pathways for the condition. Never use the abbreviation cd. Sign off as Dr. Vikranth only.\n\nReturn JSON: {"title":"Naturopathic Diet Plan for CONDITION","intro":"2-3 sentence evidence-based rationale with metabolic pathway relevance","slots":[{"time":"6:00 AM","label":"Warm Water Therapy and Movement","options":["2-4 glasses warm water plus specific exercise with duration","option 2","option 3","option 4"]},{"time":"7:00 AM","label":"Morning Therapeutic Drink","options":["specific drink with ingredients","option 2","option 3","option 4"]},{"time":"8:00 AM - 9:00 AM","label":"Breakfast","options":["specific with portions","option 2","option 3","option 4","option 5"]},{"time":"11:00 AM","label":"Mid-Morning","options":["specific","option 2","option 3","option 4","option 5"]},{"time":"12:30 PM - 1:30 PM","label":"Lunch","options":["specific with portions","option 2","option 3","option 4"]},{"time":"4:00 PM - 5:00 PM","label":"Evening","options":["specific","option 2","option 3","option 4"]},{"time":"6:30 PM - 7:30 PM","label":"Dinner","options":["specific with note","option 2","option 3","option 4"]},{"time":"8:30 PM","label":"Night Drink","options":["specific with benefit","option 2","option 3"]}],"eatMore":["food 1 - reason","food 2","food 3","food 4","food 5","food 6","food 7","food 8"],"avoid":["food 1 - reason","food 2","food 3","food 4","food 5"],"herbs":["herb - dose - benefit","herb 2 - dose - benefit","herb 3 - dose - benefit","herb 4 - dose - benefit"],"supplements":["supplement - dose - timing - rationale","supplement 2","supplement 3"],"weeklyTips":["Monday to Wednesday variation","Thursday to Friday variation","Weekend or fasting day"],"lifestyle":["specific sleep tip with time","stress management tip","hydration tip with quantities","additional tip"],"metabolicNote":"brief note on key metabolic targets addressed","note":"clinical disclaimer and follow-up","signature":"Dr. Vikranth"}';

  try {
    var raw = await callAI([{ role: 'system', content: _sys }, { role: 'user', content: prompt }], 6000);
    var chart = extractJSON(raw);
    if (!chart) {
      result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; Parse error — please try again.</div>';
      btn.disabled = false; btn.innerHTML='&#10024; Generate AI Diet Chart'; return;
    }
    renderDietChart(chart, disease, pref);
  } catch(err) {
    result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; ' + (err.message || 'Connection error') + ' &mdash; check your API key (&#128273; button) and internet, then retry.</div>';
  }
  btn.disabled = false;
  btn.innerHTML='&#10024; Generate AI Diet Chart';
}

