    return '<div style="background:'+bg+';border:1px solid '+color+'44;border-radius:9px;padding:12px 14px;margin-bottom:10px">'
      +'<div style="font-size:11px;font-weight:700;color:'+color+';text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px">'+icon+' '+label+'</div>'
