  if (out.mudTherapy && out.mudTherapy.length) {
    var mtm = out.mudTherapy.map(function(m) {
      return '<div style="background:#fff;border-radius:7px;padding:9px 11px;margin-bottom:7px;border:1px solid #d6b896">'
        +'<div style="font-size:12.5px;font-weight:700;color:#7c3d1a">🌍 '+m.application+' — '+m.area+'</div>'
        +'<div style="font-size:11px;color:#4b2c14;margin-top:4px">'
        +(m.duration?'<span style="margin-right:10px"><b>Duration:</b> '+m.duration+'</span>':'')
        +(m.frequency?'<span><b>Frequency:</b> '+m.frequency+'</span>':'')+'</div>'
        +(m.benefits?'<div style="font-size:11px;color:#1a6b3c;margin-top:3px"><b>Benefits:</b> '+m.benefits+'</div>':'')
        +(m.contraindications?'<div style="font-size:10.5px;color:#c0392b;background:#fef2f2;border-radius:5px;padding:3px 7px;margin-top:3px">&#9888; '+m.contraindications+'</div>':'')
        +'</div>';
    }).join('');
    html += sec('🌍','Mud Therapy','#b45309','#fff7ed',mtm);
  }
  if (out.massage && out.massage.length) {
    var mam = out.massage.map(function(m) {
      return '<div style="background:#fff;border-radius:7px;padding:9px 11px;margin-bottom:7px;border:1px solid #d1d5db">'
        +'<div style="font-size:12.5px;font-weight:700;color:#374151">🤲 '+m.type+' — '+m.area+'</div>'
        +'<div style="font-size:11px;color:#6b7280;margin-top:4px">'
        +(m.oil?'<span style="margin-right:8px"><b>Oil:</b> '+m.oil+'</span>':'')
        +(m.duration?'<span style="margin-right:8px"><b>Duration:</b> '+m.duration+'</span>':'')
        +(m.frequency?'<span><b>Frequency:</b> '+m.frequency+'</span>':'')+'</div>'
        +(m.benefits?'<div style="font-size:11px;color:#1a6b3c;margin-top:3px"><b>Benefits:</b> '+m.benefits+'</div>':'')
        +'</div>';
    }).join('');
    html += sec('🤲','Massage Therapy','#374151','#f9fafb',mam);
  }
  if (out.dietPlan) {
    var dp = out.dietPlan;
    var dc = (dp.principle?'<div style="font-size:12px;color:#1a6b3c;font-weight:600;margin-bottom:6px">'+dp.principle+'</div>':'')
      +(dp.eatMore&&dp.eatMore.length?'<div style="font-size:11.5px;margin-bottom:4px"><b>Eat more:</b> '+dp.eatMore.join(', ')+'</div>':'')
      +(dp.avoid&&dp.avoid.length?'<div style="font-size:11.5px;color:#c0392b;margin-bottom:4px"><b>Avoid:</b> '+dp.avoid.join(', ')+'</div>':'')
      +(dp.fasting?'<div style="font-size:11.5px;margin-bottom:4px"><b>Fasting:</b> '+dp.fasting+'</div>':'')
      +(dp.timing?'<div style="font-size:11.5px"><b>Timing:</b> '+dp.timing+'</div>':'');
    html += sec('🥗','Diet & Fasting','#064E3B','#f0fdf4',dc);
  }
  if (out.yogaAsanas && out.yogaAsanas.length) {
    var yam = '<div style="display:flex;flex-wrap:wrap;gap:6px">'
      + out.yogaAsanas.map(function(a) {
        return '<div style="background:#fff;border:1px solid #a7f3d0;border-radius:7px;padding:7px 10px;flex:1;min-width:130px">'
          +'<div style="font-size:11.5px;font-weight:700;color:#065f46">🧘 '+a.name+'</div>'
          +(a.duration?'<div style="font-size:10px;color:#0e7490">'+a.duration+'</div>':'')
          +(a.benefit?'<div style="font-size:10.5px;color:#374151;margin-top:2px">'+a.benefit+'</div>':'')
          +'</div>';
      }).join('') + '</div>';
    html += sec('🧘','Yoga & Pranayama','#065f46','#ecfdf5', yam);
  }
  if (out.pranayama && out.pranayama.length) {
    var pram = out.pranayama.map(function(p) {
      return '<div style="font-size:11.5px;padding:4px 0;border-bottom:0.5px solid #a7f3d0"><b>'+p.name+'</b>'+(p.duration?' · '+p.duration:'')+(p.benefit?' — '+p.benefit:'')+'</div>';
    }).join('');
    html += sec('🌬️','Pranayama','#0e7490','#ecfeff',pram);
  }
  if (out.acupressure && out.acupressure.length) {
    var acu = out.acupressure.map(function(a) {
      return '<div style="font-size:11.5px;padding:4px 0;border-bottom:0.5px solid #fed7aa"><b style="color:#c2410c">👆 '+a.point+'</b>'+(a.location?' — '+a.location:'')+(a.benefit?'<br><span style="color:#374151;font-size:11px">'+a.benefit+'</span>':'')+'</div>';
    }).join('');
    html += sec('👆','Acupressure','#b45309','#fff7ed',acu);
  }
  if (out.chromotherapy) html += sec('🎨','Chromotherapy','#7c3aed','#f5f3ff','<div style="font-size:11.5px">'+out.chromotherapy+'</div>');
  if (out.magneto) html += sec('🔵','Magneto Therapy','#1d4ed8','#eff6ff','<div style="font-size:11.5px">'+out.magneto+'</div>');
  if (out.lifestyle && out.lifestyle.length) {
    var lf = out.lifestyle.map(function(l){ return '<div style="font-size:11.5px;padding:3px 0;border-bottom:0.5px solid var(--bdr)">&#10003; '+l+'</div>'; }).join('');
    html += sec('🏃','Lifestyle Advice','#4f46e5','#eef2ff',lf);
  }
  if (out.duration||out.followUp) {
    html += '<div style="background:#f0fdf4;border:1px solid #a7f3d0;border-radius:9px;padding:10px 13px;margin-bottom:10px;font-size:12px;color:#065f46">'
      +(out.duration?'<div><b>Programme duration:</b> '+out.duration+'</div>':'')
      +(out.followUp?'<div><b>Follow-up:</b> '+out.followUp+'</div>':'')+'</div>';
  }
  if (out.contraindications&&out.contraindications.length) {
    html += '<div style="background:#fef2f2;border:1px solid #fca5a5;border-left:3px solid #dc2626;border-radius:8px;padding:10px 13px;font-size:11.5px;color:#7f1d1d;margin-bottom:10px"><b>&#9888; Contraindications:</b><br>'+out.contraindications.map(function(c){return '&#8226; '+c;}).join('<br>')+'</div>';
  }
  if (out.note) html += '<div style="background:#fffce8;border:1px solid #d4b84a;border-left:3px solid #f9a825;border-radius:8px;padding:10px 13px;font-size:11.5px;color:#5a4200;margin-bottom:10px"><strong>&#128203; Note:</strong> '+out.note+'</div>';
  if(out.signature){html+='<div style="margin-top:20px;padding-top:14px;border-top:1.5px solid rgba(201,168,76,.25);text-align:right;font-family:Cormorant Garamond,serif;font-size:17px;font-weight:500;color:#064E3B;letter-spacing:.05em;padding-right:4px">'+out.signature+'</div>';}
  html += '<button onclick="printChart(\'naturo-planner-result\')" class="diet-print-btn">&#128424; Print Treatment Plan</button>';
  r.innerHTML = html;
  r.scrollIntoView({behavior:'smooth',block:'start'});
}

