    html += '<div style="background:#d1fae5;border:1px solid #6ee7b7;border-radius:9px;padding:11px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#065f46;text-transform:uppercase;margin-bottom:7px">&#9728;&#65039; Daily Schedule During Fast</div>'
      + (ds.morning?'<div style="font-size:12px;padding:4px 0;border-bottom:0.5px solid #6ee7b7;color:#064e3b"><b>&#127774; Morning:</b> '+ds.morning+'</div>':'')
      + (ds.midday?'<div style="font-size:12px;padding:4px 0;border-bottom:0.5px solid #6ee7b7;color:#064e3b"><b>&#9728;&#65039; Midday:</b> '+ds.midday+'</div>':'')
      + (ds.evening?'<div style="font-size:12px;padding:4px 0;color:#064e3b"><b>&#127769; Evening:</b> '+ds.evening+'</div>':'')
      + '</div>';
  }
  if (out.breakFast) {
    var bf = out.breakFast;
    html += '<div style="background:#fff8e1;border:1px solid #ffe082;border-radius:9px;padding:11px 14px;margin-bottom:10px">'
      + '<div style="font-size:11px;font-weight:700;color:#f57f17;text-transform:uppercase;margin-bottom:7px">&#127859; Breaking the Fast</div>'
      + (bf.timing?'<div style="font-size:12px;padding:3px 0;border-bottom:0.5px solid #ffe082;color:#5a4200"><b>When:</b> '+bf.timing+'</div>':'')
      + (bf.firstFood?'<div style="font-size:12px;padding:3px 0;border-bottom:0.5px solid #ffe082;color:#5a4200"><b>First Food:</b> '+bf.firstFood+'</div>':'')
      + (bf.progression?'<div style="font-size:12px;padding:3px 0;color:#5a4200"><b>Progression:</b> '+bf.progression+'</div>':'')
      + '</div>';
  }
  var allowHtml = '';
  if (out.allowed&&out.allowed.length){allowHtml='<div style="flex:1;min-width:140px"><div style="font-size:11px;font-weight:700;color:#1b5e20;margin-bottom:5px">&#9989; Allowed</div>'+out.allowed.map(function(a){return '<div style="font-size:11.5px;color:#1b5e20;padding:2px 0">&#8226; '+a+'</div>';}).join('')+'</div>';}
  var prohibHtml = '';
  if (out.prohibited&&out.prohibited.length){prohibHtml='<div style="flex:1;min-width:140px"><div style="font-size:11px;font-weight:700;color:#880e4f;margin-bottom:5px">&#10060; Prohibited</div>'+out.prohibited.map(function(a){return '<div style="font-size:11.5px;color:#880e4f;padding:2px 0">&#8226; '+a+'</div>';}).join('')+'</div>';}
  if (allowHtml||prohibHtml){html+='<div style="display:flex;gap:10px;flex-wrap:wrap;background:var(--surf);border:1px solid var(--bdr);border-radius:9px;padding:11px 14px;margin-bottom:10px">'+allowHtml+prohibHtml+'</div>';}
  if (out.herbalSupport&&out.herbalSupport.length){html+='<div style="background:#fff8e1;border:1px solid #ffe082;border-radius:9px;padding:11px 14px;margin-bottom:10px"><div style="font-size:11px;font-weight:700;color:#b45309;text-transform:uppercase;margin-bottom:6px">&#127807; Herbal Support</div>'+out.herbalSupport.map(function(h){return '<div style="font-size:12px;padding:3px 0;border-bottom:0.5px solid #ffe082;color:#5a4200">&#8226; '+h+'</div>';}).join('')+'</div>';}
  if (out.monitoring&&out.monitoring.length){html+='<div style="background:#fce4ec;border:1px solid #f48fb1;border-radius:9px;padding:11px 14px;margin-bottom:10px"><div style="font-size:11px;font-weight:700;color:#880e4f;text-transform:uppercase;margin-bottom:6px">&#128065; Monitor During Fast</div>'+out.monitoring.map(function(m){return '<div style="font-size:12px;padding:4px 0;border-bottom:0.5px solid #f48fb1"><b style="color:#880e4f">'+m.symptom+':</b> <span style="color:#7f1d1d">'+m.action+'</span></div>';}).join('')+'</div>';}
  if (out.contraindications&&out.contraindications.length){html+='<div style="background:#fef2f2;border:1px solid #fca5a5;border-left:3px solid #dc2626;border-radius:8px;padding:10px 13px;margin-bottom:10px"><div style="font-size:11px;font-weight:700;color:#991b1b;text-transform:uppercase;margin-bottom:5px">&#128683; Contraindications</div>'+out.contraindications.map(function(c3){return '<div style="font-size:12px;color:#7f1d1d;padding:2px 0">&#8226; '+c3+'</div>';}).join('')+'</div>';}
  if (out.note){html+='<div style="background:#fef2f2;border:1px solid #fca5a5;border-left:3px solid #dc2626;border-radius:8px;padding:10px 13px;font-size:11.5px;color:#7f1d1d;line-height:1.6;margin-bottom:10px"><strong>&#9888;:</strong> '+out.note+'</div>';}
  html+='<button onclick="printChart(\'fast-result\')" class="diet-print-btn">&#128424; Print Fasting Protocol</button>';
  r.innerHTML=html; r.scrollIntoView({behavior:'smooth',block:'start'});
}

functions.generateFastingPlan:
async function generateFastingPlan() {
  var result = document.getElementById('fast-result');
  var btn    = document.getElementById('fast-btn');
  var _mainInput=document.getElementById('fast-disease').value.trim();var _age=document.getElementById('fast-age').value;var _status=document.getElementById('fast-status').value;var _exp=document.getElementById('fast-exp').value;var _supervision=document.getElementById('fast-supervision')?document.getElementById('fast-supervision').value:'home self-supervised';var _season=document.getElementById('fast-season')?document.getElementById('fast-season').value:'temperate';var _fastMeds=document.getElementById('fast-meds')?document.getElementById('fast-meds').value:'';
  if (!_mainInput) {
    result.innerHTML = '<div style="color:#c0392b;padding:9px 12px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; Please fill in the required field.</div>';
    return;
  }
  if (needsKey()) { needsKeyCheck('fast-result', 'Generate Fasting Protocol'); return; }
  if (!isOnline()) { showOfflineBanner('fast-result', 'Generate Fasting Protocol'); return; }
  btn.disabled = true; btn.textContent = 'Generating...';
  result.innerHTML = '<div style="text-align:center;padding:36px 20px;font-size:13px;color:#555"><div style="font-size:30px;animation:diet-spin 1.2s linear infinite;display:inline-block;margin-bottom:10px">&#9889;</div><br>' + 'Designing fasting protocol for <b>' + _mainInput + '</b>...<br><span style="font-size:11px;opacity:.6;margin-top:4px;display:block">Usually 10-15 seconds</span></div>';
  var _fastSys = 'You are an expert BNYS naturopathic physician specialising in therapeutic fasting. Respond ONLY with valid JSON (no markdown, no backticks).';
  var prompt = 'Disease: ' + _mainInput
    + '\nAge: ' + (_age||'adult')
    + '\nHealth status: ' + _status
    + '\nFasting experience: ' + _exp
    + '\nSupervision level: ' + _supervision
    + '\nSeason and climate: ' + _season
    + (_fastMeds?'\nCurrent medications (safety check required): '+_fastMeds:'')
    + '\n\nDesign a complete therapeutic fasting protocol. All schedules must use specific times. Flag any medication interactions or contraindications. Provide day-by-day schedule. Never use cd. Sign as Dr. Vikranth.\n\nRespond ONLY with valid JSON (no markdown):{"title":"Therapeutic Fasting Protocol — Dr. Vikranth","intro":"rationale for fasting in this condition (3-4 sentences with metabolic basis)","safetyCheck":"medication safety assessment and any adjustments needed","fastingType":"recommended fasting type","duration":"recommended duration","phases":[{"phase":"phase name","duration":"duration","instructions":"detailed time-based instructions"}],"dailySchedule":[{"time":"6:00 AM","activity":"specific activity"},{"time":"7:00 AM","activity":"activity"},{"time":"9:00 AM","activity":"activity"},{"time":"12:00 PM","activity":"activity"},{"time":"3:00 PM","activity":"activity"},{"time":"6:00 PM","activity":"activity"},{"time":"8:30 PM","activity":"activity"}],"allowed":["allowed item with quantity and timing"],"prohibited":["prohibited item with reason"],"herbalSupport":["herb — dose — timing — benefit"],"monitoring":[{"symptom":"symptom to watch","action":"what to do"}],"refeeding":{"day1":"first day after fasting","day2-3":"gradual reintroduction","week1":"first week after"},"seasonalAdaptations":"specific adjustments for the stated season","contraindications":["contraindication"],"note":"safety disclaimer","signature":"Dr. Vikranth"}'
  try {
    var raw = await callAI([{ role: 'system', content: _fastSys }, { role: 'user', content: prompt }], 5000);
    var out = extractJSON(raw);
    if (!out) { result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; Parse error — please try again.</div>'; btn.disabled=false; btn.innerHTML='&#10024; Generate Fasting Protocol'; return; }
    renderFastingPlan(out);
  } catch(e) {
    result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; ' + (e.message || 'Connection error') + ' &mdash; check your API key and internet connection, then retry.</div>';
  }
  btn.disabled=false; btn.innerHTML='&#10024; Generate Fasting Protocol';
}

