        + (p.benefit ? '<div style="font-size:11.5px;color:#0c4a6e;margin-bottom:4px">' + p.benefit + '</div>' : '')
        + (p.technique ? '<div style="font-size:11px;color:#075985;line-height:1.5">' + p.technique + '</div>' : '')
        + '</div>';
