      + (m.benefit ? '<div style="font-size:11.5px;color:#4c1d95;margin-bottom:4px">' + m.benefit + '</div>' : '')
      + (m.instructions ? '<div style="font-size:11px;color:#5b21b6;line-height:1.55">' + m.instructions + '</div>' : '')
