functions.generateYogaChart:
async function generateYogaChart() {
  var disease = document.getElementById('yoga-disease').value.trim();
  var age     = document.getElementById('yoga-age').value.trim();
  var gender  = document.getElementById('yoga-gender').value;
  var level   = document.getElementById('yoga-level').value;
  var contra  = document.getElementById('yoga-contra').value.trim();
  var session = (document.getElementById('yoga-session')||{value:'therapeutic healing'}).value;
  var timeAvail = (document.getElementById('yoga-time')||{value:'30 minutes'}).value;
  var goal    = (document.getElementById('yoga-goal')||{value:'healing and recovery'}).value;
  var result  = document.getElementById('yoga-result');
  var btn     = document.getElementById('yoga-btn');

  if (!disease) {
    result.innerHTML = '<div style="color:#c0392b;font-size:12px;padding:8px 12px;'
      + 'background:#fef2f2;border-radius:7px;border:1px solid #fca5a5">'
      + '&#9888; Please enter a disease or condition.</div>';
    return;
  }
  if (needsKeyCheck('yoga-result', 'AI Therapeutic Yoga Planner')) return;
  if (!isOnline()) { showOfflineBanner('yoga-result', 'AI Therapeutic Yoga Planner'); return; }

  btn.disabled = true;
  btn.textContent = 'Generating...';
  result.innerHTML = '<div style="text-align:center;padding:40px 20px;color:#0e7490;font-size:13px">'
    + '<div style="display:inline-block;font-size:32px;animation:diet-spin 1.2s linear infinite;margin-bottom:10px">&#129496;</div>'
    + '<br>Building yoga protocol for <b>' + disease + '</b>...<br>'
    + '<span style="font-size:11px;opacity:.7;margin-top:4px;display:block">Usually 10-15 seconds</span></div>';

  var _yogaSys = 'You are an expert BNYS yoga therapist. Respond ONLY with valid JSON (no markdown, no backticks).';
  var prompt = 'Generate a therapeutic yoga protocol for:\n'
    + 'Disease: ' + disease + '\nAge: ' + (age || 'adult')
    + '\nGender: ' + gender + '\nFitness Level: ' + level
    + '\nSession Type: ' + session
    + '\nTime Available: ' + timeAvail
    + '\nPrimary Goal: ' + goal
    + '\nContraindications: ' + (contra || 'none') + '\n\n'
    + 'Respond ONLY with valid JSON (no markdown backticks):\n'
    + '{"title":"Therapeutic Yoga Protocol for [Disease]",'
    + '"intro":"2-sentence overview and evidence base",'
    + '"asanas":[{"name":"Sanskrit name","english":"English name","duration":"time/rounds",'
    + '"benefit":"specific benefit for this disease","technique":"brief steps","contraindication":"who should avoid"}],'
    + '"pranayama":[{"name":"name","duration":"time","benefit":"benefit","technique":"how to"}],'
    + '"meditation":{"name":"type","duration":"time","benefit":"benefit","instructions":"brief guide"},'
    + '"weeklySchedule":[{"day":"Monday","session":"Morning","duration":"30 mins","practice":"practices for the day"}],'
    + '"precautions":["precaution1","precaution2"],'
    + '"lifestyle":["tip1","tip2","tip3"],'
    + '"note":"clinical disclaimer"}'
    + '\nInclude 6-10 asanas, 2-4 pranayama, all 7 days. Be specific.';

  try {
    var raw = await callAI([{ role: 'system', content: _yogaSys }, { role: 'user', content: prompt }], 5000);
    var chart = extractJSON(raw);
    if (!chart) {
      result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; Parse error — please try again.</div>';
      btn.disabled = false; btn.innerHTML='&#10024; Generate AI Yoga Protocol'; return;
    }
    renderYogaChart(chart);
  } catch(err) {
    result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; ' + (err.message || 'Connection error') + ' &mdash; check your API key (&#128273; button) and internet, then retry.</div>';
  }
  btn.disabled = false;
  btn.innerHTML='&#10024; Generate AI Yoga Protocol';
}

