  if (out.note) { html += '<div style="background:#fef2f2;border:1px solid #fca5a5;border-left:3px solid #dc2626;border-radius:8px;padding:10px 13px;font-size:11.5px;color:#7f1d1d;line-height:1.6;margin-bottom:10px"><strong>&#9888;:</strong> '+out.note+'</div>'; }
  html += '<button onclick="printChart(\'dp-result\')" class="diet-print-btn">&#128424; Print Protocol</button>';
  r.innerHTML = html; r.scrollIntoView({behavior:'smooth',block:'start'});
}

functions.generateDiseaseProto:
async function generateDiseaseProto() {
  var result = document.getElementById('diseaseproto-result');
  var btn    = document.getElementById('dp-btn');
  var _mainInput=document.getElementById('dp-disease').value.trim();var _stage=document.getElementById('dp-stage').value;var _age=document.getElementById('dp-age').value;var _diet=document.getElementById('dp-diet').value;
  var _setting=(document.getElementById('dp-setting')||{value:'outpatient clinic'}).value;
  var _dpDuration=(document.getElementById('dp-duration')||{value:'4 weeks'}).value;
  var _dpContra=(document.getElementById('dp-contra')||{value:''}).value;
  if (!_mainInput) {
    result.innerHTML = '<div style="color:#c0392b;padding:9px 12px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; Please fill in the required field.</div>';
    return;
  }
  if (needsKey()) { needsKeyCheck('dp-result', 'Generate BNYS Protocol'); return; }
  if (!isOnline()) { showOfflineBanner('dp-result', 'Generate BNYS Protocol'); return; }
  btn.disabled = true; btn.textContent = 'Generating...';
  result.innerHTML = '<div style="text-align:center;padding:36px 20px;font-size:13px;color:#555"><div style="font-size:30px;animation:diet-spin 1.2s linear infinite;display:inline-block;margin-bottom:10px">&#127973;</div><br>' + 'Generating BNYS protocol for <b>' + _mainInput + '</b>...<br><span style="font-size:11px;opacity:.6;margin-top:4px;display:block">Usually 10-15 seconds</span></div>';
  var _sys2 = 'You are an expert clinical AI assistant supporting a Naturopathy and Yogic Sciences (BNYS) practice. Your primary responsibility is to generate structured, practical, and medically sound wellness and diet plans based on the patient symptoms, vitals, or diagnoses provided by the attending physician.\n\nClinical Guidelines:\n- Ground all recommendations in evidence-based naturopathic principles, clinical nutrition, hydrotherapy, and therapeutic yoga.\n- When relevant, factor in metabolic health and biochemical pathways (e.g., intracellular mineral balance such as magnesium and phosphate) to support deep cellular healing.\n- Maintain a highly professional, clinical, yet patient-friendly tone.\n\nStrict Formatting Rules:\n- All daily routines and diet plans MUST use specific times (e.g., 6:00 AM, 8:00 AM, 12:30 PM). Never group by broad categories alone.\n- NEVER use the abbreviation cd under any circumstances. Write all instructions clearly.\n- Every plan must end with the signature: Dr. Vikranth — the name only, no preceding words like Regards or Sincerely.\n\nRespond ONLY with valid JSON (no markdown, no backticks).';
  var prompt = 'Disease: ' + _mainInput
    + '\nStage: ' + _stage
    + '\nAge: ' + (_age||'adult')
    + '\nTreatment setting: ' + _setting
    + '\nDiet preference: ' + _diet
    + '\nProgramme duration: ' + _dpDuration
    + (_dpContra?'\nComorbidities and contraindications: '+_dpContra:'')
    + '\n\nGenerate a complete BNYS management protocol. Use specific times for all schedules. Address metabolic pathways. Never use cd. Sign as Dr. Vikranth only.\n\nReturn JSON: {"title":"BNYS Protocol for DISEASE","overview":"3-4 sentence overview with metabolic rationale","goals":["goal 1","goal 2","goal 3"],"dailyRoutine":[{"time":"6:00 AM","activity":"specific"},{"time":"7:00 AM","activity":"activity"},{"time":"8:00 AM","activity":"breakfast"},{"time":"10:00 AM","activity":"treatment"},{"time":"12:30 PM","activity":"lunch"},{"time":"4:00 PM","activity":"treatment"},{"time":"6:00 PM","activity":"yoga or walk"},{"time":"8:30 PM","activity":"night routine"}],"diet":{"principles":"principles with metabolic rationale","include":["food 1 - reason","food 2","food 3","food 4","food 5"],"avoid":["food 1 - reason","food 2","food 3"],"fasting":"specific fasting recommendation"},"yoga":{"asanas":[{"name":"asana","duration":"duration","benefit":"specific benefit"}],"pranayama":"specific pranayama with duration","duration":"total session duration"},"hydrotherapy":[{"treatment":"name","temperature":"specific temp in Celsius","technique":"technique","duration":"duration","frequency":"times per week"}],"herbs":[{"name":"herb","dose":"specific dose","timing":"time of day","benefit":"specific benefit"}],"acupressure":[{"point":"code and name","location":"precise location","benefit":"specific benefit"}],"lifestyle":["tip 1","tip 2","tip 3","tip 4"],"monitoring":["parameter to monitor"],"contraindications":["caution 1","caution 2"],"referral":"specific criteria for conventional referral","note":"clinical disclaimer","signature":"Dr. Vikranth"}';
  try {
    var raw = await callAI([{ role: 'system', content: _sys2 }, { role: 'user', content: prompt }], 6000);
    var out = extractJSON(raw);
    if (!out) { result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; Parse error — please try again.</div>'; btn.disabled=false; btn.innerHTML='&#10024; Generate BNYS Protocol'; return; }
    renderDiseaseProto(out);
  } catch(e) {
    result.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; ' + (e.message || 'Connection error') + ' &mdash; check your API key and internet connection, then retry.</div>';
  }
  btn.disabled=false; btn.innerHTML='&#10024; Generate BNYS Protocol';
}

functions.renderSOAP:
function renderSOAP(out) {
  var r = document.getElementById('soap-result');
  function section(letter, color, bg, content) {
    return '<div style="background:'+bg+';border:1.5px solid '+color+'44;border-radius:10px;margin-bottom:10px;overflow:hidden">'
      + '<div style="background:'+color+';color:#fff;padding:8px 14px;font-size:13px;font-weight:700">'+letter+'</div>'
      + '<div style="padding:11px 14px;font-size:12.5px;color:var(--tx);line-height:1.7">'+content+'</div>'
      + '</div>';
  }
  var html = '<div style="background:linear-gradient(135deg,#1d4ed8,#1e40af);border-radius:11px;padding:14px 16px;margin-bottom:14px;color:#fff">'
    + '<div style="font-size:15px;font-weight:700">&#128203; SOAP Note + BNYS Treatment Plan</div>'
    + '<div style="font-size:12px;opacity:.85;margin-top:3px">' + (out.title||'') + (out.date?' &mdash; '+out.date:'') + '</div>'
    + '</div>';
  if (out.S) {
    var s = out.S;
    html += section('S — Subjective','#1d4ed8','#eff6ff',
      (s.cc?'<div><b>CC:</b> '+s.cc+'</div>':'')
      +(s.hpi?'<div><b>HPI:</b> '+s.hpi+'</div>':'')
      +(s.pmh?'<div><b>PMH:</b> '+s.pmh+'</div>':'')
      +(s.meds?'<div><b>Medications:</b> '+s.meds+'</div>':'')
    );
  }
  if (out.O) {
    var o = out.O;
    html += section('O — Objective','#0e7490','#ecfeff',
      (o.vitals?'<div><b>Vitals:</b> '+o.vitals+'</div>':'')
      +(o.exam?'<div><b>Examination:</b> '+o.exam+'</div>':'')
      +(o.labs?'<div><b>Investigations:</b> '+o.labs+'</div>':'')
    );
  }
  if (out.A) {
    var a = out.A;
    var diffHtml = (a.differentials&&a.differentials.length)
      ? '<div><b>Differentials:</b> '+a.differentials.map(function(d,i){return '<span style="background:#e0f2fe;color:#075985;border-radius:4px;padding:1px 7px;margin:2px;display:inline-block">'+d+'</span>';}).join('')+'</div>' : '';
    html += section('A — Assessment','#7c3aed','#f5f3ff',
      (a.primary?'<div><b>Primary Dx:</b> '+a.primary+'</div>':'')
      +diffHtml
      +(a.naturopathicAssessment?'<div style="margin-top:5px"><b>&#127807; Naturopathic Assessment:</b> '+a.naturopathicAssessment+'</div>':'')
    );
  }
  if (out.P) {
    var p = out.P;
    var invHtml = (p.investigations&&p.investigations.length)
      ? '<div><b>Investigations:</b> '+p.investigations.map(function(i){return '&#8226; '+i;}).join(' ')+'</div>' : '';
    var natHtml = '';
    if (p.naturopathic) {
      var n = p.naturopathic;
      natHtml = '<div style="background:#f0fdf4;border-radius:7px;padding:8px 10px;margin-top:8px">'
        + '<div style="font-weight:700;color:#1b5e20;margin-bottom:5px;font-size:12px">&#127807; BNYS Treatment Plan</div>'
        + (n.diet?'<div style="font-size:12px;padding:2px 0;border-bottom:0.5px solid #a5d6a7"><b>Diet:</b> '+n.diet+'</div>':'')
        + (n.yoga?'<div style="font-size:12px;padding:2px 0;border-bottom:0.5px solid #a5d6a7"><b>Yoga:</b> '+n.yoga+'</div>':'')
        + (n.hydrotherapy?'<div style="font-size:12px;padding:2px 0;border-bottom:0.5px solid #a5d6a7"><b>Hydrotherapy:</b> '+n.hydrotherapy+'</div>':'')
        + (n.herbs?'<div style="font-size:12px;padding:2px 0;border-bottom:0.5px solid #a5d6a7"><b>Herbs:</b> '+n.herbs+'</div>':'')
        + (n.acupressure?'<div style="font-size:12px;padding:2px 0;border-bottom:0.5px solid #a5d6a7"><b>Acupressure:</b> '+n.acupressure+'</div>':'')
        + (n.lifestyle?'<div style="font-size:12px;padding:2px 0"><b>Lifestyle:</b> '+n.lifestyle+'</div>':'')
        + '</div>';
    }
    html += section('P — Plan','#065f46','#f0fdf4',
      invHtml + natHtml
      +(p.conventional?'<div style="margin-top:5px"><b>Conventional referral:</b> '+p.conventional+'</div>':'')
      +(p.followUp?'<div><b>Follow-up:</b> '+p.followUp+'</div>':'')
    );
  }
  if (out.clinicalPearl) {
    html += '<div style="background:#fffce8;border:1px solid #d4b84a;border-left:3px solid #f9a825;border-radius:8px;padding:10px 13px;font-size:12.5px;color:#5a4200;line-height:1.6;margin-bottom:10px">&#128161; <strong>Clinical Pearl:</strong> '+out.clinicalPearl+'</div>';
  }
  if (out.note) { html += '<div style="background:#fef2f2;border:1px solid #fca5a5;border-left:3px solid #dc2626;border-radius:8px;padding:10px 13px;font-size:11.5px;color:#7f1d1d;line-height:1.6;margin-bottom:10px"><strong>&#9888;:</strong> '+out.note+'</div>'; }
  html += '<button onclick="printChart(\'soap-result\')" class="diet-print-btn">&#128424; Print SOAP Note</button>';
  r.innerHTML = html; r.scrollIntoView({behavior:'smooth',block:'start'});
}

functions.generateSOAP:
