  var _mainInput=document.getElementById('soap-cc').value.trim();var _demo=document.getElementById('soap-demo').value;var _visit=document.getElementById('soap-visit')?document.getElementById('soap-visit').value:'new patient';var _spec=document.getElementById('soap-spec')?document.getElementById('soap-spec').value:'general BNYS';var _vitals=document.getElementById('soap-vitals').value;var _sx=document.getElementById('soap-sx').value;var _exam=document.getElementById('soap-exam').value;var _labs=document.getElementById('soap-labs').value;var _prev=document.getElementById('soap-prev')?document.getElementById('soap-prev').value:'';
  if (!_mainInput) {
