functions.calcVitals:
function calcVitals() {
  var result = document.getElementById('vitals-result');
  var age=+document.getElementById('vt-age').value, gen=document.getElementById('vt-gen').value;
  var wt=+document.getElementById('vt-wt').value, ht=+document.getElementById('vt-ht').value;
  var sbp=+document.getElementById('vt-sbp').value, dbp=+document.getElementById('vt-dbp').value;
  var hr=+document.getElementById('vt-hr').value, temp=+document.getElementById('vt-temp').value;
  var spo2=+document.getElementById('vt-spo2').value, rr=+document.getElementById('vt-rr').value;
  var waist=+document.getElementById('vt-waist').value, rbg=+document.getElementById('vt-rbg').value;
  if (!wt || !ht) { result.innerHTML='<div style="color:#c0392b;padding:9px 12px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">&#9888; Please enter at least Weight and Height.</div>'; return; }

  function vcard(label, value, unit, status, color, bg, note, nat) {
    return '<div style="background:'+bg+';border:1.5px solid '+color+'44;border-radius:10px;padding:12px 14px">'
      + '<div style="font-size:10.5px;font-weight:700;color:'+color+';text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px">'+label+'</div>'
      + '<div style="font-size:22px;font-weight:800;color:'+color+'">'+value+'<span style="font-size:12px;font-weight:400;margin-left:3px">'+unit+'</span></div>'
      + '<div style="font-size:11.5px;font-weight:600;color:'+color+';margin-top:2px">'+status+'</div>'
      + (note?'<div style="font-size:11px;color:#555;margin-top:4px;line-height:1.5">'+note+'</div>':'')
      + (nat?'<div style="font-size:11px;color:#1a6b3c;background:#f0fdf4;border-radius:5px;padding:4px 7px;margin-top:5px;line-height:1.4">&#127807; '+nat+'</div>':'')
      + '</div>';
  }

  var items = [];

  // BMI
  var bmi = (wt/(ht/100)/(ht/100)).toFixed(1);
  var bmiC,bmiS,bmiN;
  if (bmi<18.5){bmiC='#1d4ed8';bmiS='Underweight';bmiN='Ashwagandha, calorie-dense whole foods, Shatavari';}
  else if (bmi<23){bmiC='#1a6b3c';bmiS='Normal';bmiN='Maintain with seasonal diet + daily yoga';}
  else if (bmi<25){bmiC='#b45309';bmiS='Normal / Asian: Overweight';bmiN='Triphala, low-GI diet, Surya Namaskar';}
  else if (bmi<27.5){bmiC='#b45309';bmiS='Overweight';bmiN='Guggulu, intermittent fasting, brisk walk 45min';}
  else if (bmi<30){bmiC='#c0392b';bmiS='Obese I (Asian)';bmiN='Medohar Guggulu, supervised fasting, Kapalbhati';}
  else{bmiC='#7a0d0d';bmiS='Obese II/III';bmiN='Multi-disciplinary management + naturo-adjunct';}
  items.push(vcard('BMI',bmi,'kg/m²',bmiS,bmiC,bmiC+'11','South Asian cutoff: Overweight ≥23, Obese ≥27.5',bmiN));

  // BP
  if (sbp && dbp) {
    var bpC,bpS,bpN;
    if (sbp<90||dbp<60){bpC='#1d4ed8';bpS='Hypotension';bpN='Increase water + salt, Ashwagandha, avoid prolonged standing';}
    else if (sbp<120&&dbp<80){bpC='#1a6b3c';bpS='Normal';bpN='Maintain with DASH diet + daily Anulom Vilom';}
    else if (sbp<130&&dbp<80){bpC='#4a9a5e';bpS='Elevated';bpN='DASH diet, reduce sodium, Sarpagandha herb, Shavasana';}
    else if (sbp<140||dbp<90){bpC='#b45309';bpS='Stage 1 Hypertension';bpN='Sarpagandha, garlic, hip bath, Yoga Nidra daily';}
    else if (sbp<180||dbp<120){bpC='#c0392b';bpS='Stage 2 Hypertension';bpN='Medical management + naturo-adjunct; Shavasana, low-sodium diet';}
    else{bpC='#7a0d0d';bpS='Hypertensive Crisis';bpN='EMERGENCY — refer immediately';}
    items.push(vcard('Blood Pressure',sbp+'/'+dbp,'mmHg',bpS,bpC,bpC+'11','Normal: <120/80 mmHg',bpN));
  }

  // Heart Rate
  if (hr) {
    var hrC,hrS,hrN;
    if (hr<50){hrC='#1d4ed8';hrS='Bradycardia';hrN='Check thyroid; Ashwagandha if not cardiac cause';}
    else if (hr<=60){hrC='#4a9a5e';hrS='Athletic / Low normal';hrN='Good cardiovascular fitness — maintain';}
    else if (hr<=100){hrC='#1a6b3c';hrS='Normal';hrN='Anulom Vilom 10 min daily maintains vagal tone';}
    else if (hr<=120){hrC='#b45309';hrS='Tachycardia (mild)';hrN='Bhramari pranayama, Ashwagandha, reduce caffeine';}
    else{hrC='#c0392b';hrS='Significant Tachycardia';hrN='Investigate cause; refer if persistent';}
    items.push(vcard('Heart Rate',hr,'bpm',hrS,hrC,hrC+'11','Normal: 60–100 bpm',hrN));
  }

  // SpO2
  if (spo2) {
    var spC,spS,spN;
    if (spo2>=97){spC='#1a6b3c';spS='Normal';spN='Pranayama + deep breathing daily';}
    else if (spo2>=94){spC='#b45309';spS='Borderline Low';spN='Bhastrika pranayama, assess for anaemia/lung issue';}
    else{spC='#c0392b';spS='Low — Hypoxia';spN='Medical evaluation needed urgently';}
    items.push(vcard('SpO₂',spo2,'%',spS,spC,spC+'11','Normal: ≥97%',spN));
  }

  // Temperature
  if (temp) {
    var tmpC,tmpS,tmpN;
    if (temp<97){tmpC='#1d4ed8';tmpS='Hypothermia';tmpN='Warm compresses, ginger tea, dry blanket wrap';}
    else if (temp<=99){tmpC='#1a6b3c';tmpS='Normal';tmpN='Normal — no intervention';}
    else if (temp<=100.4){tmpC='#b45309';tmpS='Low-grade Fever';tmpN='Wet pack on forehead, tulsi-ginger tea, rest';}
    else if (temp<=103){tmpC='#c0392b';tmpS='Fever';tmpN='Cold pack abdomen + forehead, rest, Tulsi + Giloy decoction';}
    else{tmpC='#7a0d0d';tmpS='High Fever';tmpN='Medical management + tepid sponging, monitor closely';}
    items.push(vcard('Temperature',temp,'°F',tmpS,tmpC,tmpC+'11','Normal: 97–99°F',tmpN));
  }

  // Respiratory Rate
  if (rr) {
    var rrC,rrS,rrN;
    if (rr<12){rrC='#1d4ed8';rrS='Bradypnoea';rrN='Check sedation/CNS; Bhastrika pranayama when clear';}
    else if (rr<=20){rrC='#1a6b3c';rrS='Normal';rrN='Maintain with Pranayama daily';}
    else if (rr<=25){rrC='#b45309';rrS='Mildly Elevated';rrN='Deep diaphragmatic breathing, Anulom Vilom';}
    else{rrC='#c0392b';rrS='Tachypnoea';rrN='Assess for cardiac/respiratory cause urgently';}
    items.push(vcard('Resp Rate',rr,'/min',rrS,rrC,rrC+'11','Normal: 12–20/min',rrN));
  }

  // Waist circumference
  if (waist) {
    var wC,wS,wN;
    var wHigh = gen==='M' ? 90 : 80;
    var wBorder = gen==='M' ? 85 : 75;
    if (waist<=wBorder){wC='#1a6b3c';wS='Normal';wN='Maintain with core yoga + healthy diet';}
    else if (waist<=wHigh){wC='#b45309';wS='Borderline (Metabolic risk)';wN='Triphala, Kapalbhati 10min, low-carb diet';}
    else{wC='#c0392b';wS='Abdominal Obesity';wN='Medohar Guggulu, Agnisara, caloric restriction';}
    items.push(vcard('Waist',waist,'cm',wS+' ['+(gen==='M'?'M: <85 low, <90 mod]':'F: <75 low, <80 mod]'),wC,wC+'11','WHO Asian: M <90cm, F <80cm',wN));
  }

  // Random Blood Glucose
  if (rbg) {
    var rgC,rgS,rgN;
    if (rbg<100){rgC='#1a6b3c';rgS='Normal';rgN='Maintain with low-GI diet, exercise';}
    else if (rbg<140){rgC='#4a9a5e';rgS='Normal (post-meal context)';rgN='Bitter gourd juice, Fenugreek seeds, Gymnema';}
