functions.anatAskAI:
async function anatAskAI() {
  var inp = document.getElementById('anat-ai-input');
  var res = document.getElementById('anat-ai-result');
  if (!inp || !res) return;
  var q = (inp.value || '').trim();
  if (!q) { inp.focus(); return; }

  var cacheKey = 'anat_' + ccNormKey(q);

  // 1. Memory cache (instant)
  if (_anatAiMemCache[cacheKey]) {
    res.innerHTML = _anatAiMemCache[cacheKey];
    return;
  }

  res.innerHTML = '<div class="ddx-loading"><div class="ddx-spinner"></div><span>Checking cloud cache…</span></div>';

  // 2. Firebase cache
  if (ccIsConfigured()) {
    try {
      await ccInitFirebase();
      var doc = await _fbDb.collection('ccr_anat_cache').doc(cacheKey).get();
      if (doc.exists) {
        var html = doc.data().html;
        _anatAiMemCache[cacheKey] = html;
        res.innerHTML = html;
        return;
      }
    } catch(e) { console.warn('Anat Firebase read failed:', e.message); }
  }

  // 3. Call AI
  res.innerHTML = '<div class="ddx-loading"><div class="ddx-spinner"></div><span>Generating A&amp;P explanation…</span></div>';

  var SYS = 'You are a medical anatomy and physiology professor. '
    + 'Answer precisely and completely with exam-quality content. '
    + 'Structure your response with clear sections. Cover: definition, key anatomy, mechanism/physiology, key numbers/values, clinical relevance. '
    + 'STRICT: Return ONLY clean HTML. No markdown. No backticks. No preamble. '
    + 'Use: <h4 style="color:#0e7490;margin:12px 0 5px;font-size:13px"> for headers, '
    + '<p style="font-size:13px;line-height:1.7;margin:0 0 8px"> for paragraphs, '
    + '<ul style="margin:5px 0 10px;padding-left:18px"><li style="font-size:13px;margin-bottom:3px"> for lists, '
    + '<table class="tbl"><thead><tr><th> for tables. '
    + 'Start directly with content — no greeting.';

  try {
    var raw = await callAI([
      {role:'system', content:SYS},
      {role:'user', content:'A&P question: ' + q}
    ], 1400);

    var html = raw.replace(/```html?/gi,'').replace(/```/g,'').trim();
    var out = '<div style="background:var(--sky-lt);border:1px solid #b0d4e8;border-radius:12px;padding:14px 16px">'
      + '<div style="font-size:10px;font-weight:700;color:#0e7490;text-transform:uppercase;letter-spacing:.08em;margin-bottom:10px;display:flex;align-items:center;gap:6px">'
      + '🤖 AI Response'
      + '<span style="background:#0e7490;color:#fff;border-radius:10px;padding:1px 8px;font-size:9px">☁️ Saved to Cloud</span>'
      + '</div>'
      + html
      + '</div>';

    _anatAiMemCache[cacheKey] = out;
    res.innerHTML = out;

    // 4. Save to Firebase
    if (ccIsConfigured()) {
      try {
        await ccInitFirebase();
        await _fbDb.collection('ccr_anat_cache').doc(cacheKey).set({
          html: out, query: q, savedAt: new Date().toISOString()
        });
      } catch(e) { console.warn('Anat Firebase write failed:', e.message); }
    }
  } catch(e) {
    res.innerHTML = '<div style="color:#c0392b;padding:10px;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;font-size:12px">⚠️ ' + (e.message||'Error') + ' — check API key and retry.</div>';
  }
}

