functions.liHandleFile:
async function liHandleFile(file) {
  if (!file) return;
  var ta = document.getElementById('li-input');
  var maxMB = 10;
  if (file.size > maxMB * 1024 * 1024) {
    liSetStatus('&#9888; File too large. Please use files under ' + maxMB + 'MB.', 'error');
    return;
  }
  var name = file.name.toLowerCase();
  var isPDF = file.type === 'application/pdf' || name.endsWith('.pdf');
  var isImg = file.type.startsWith('image/') || /\.(jpg|jpeg|png|gif|bmp|webp|heic|heif|tiff?)$/i.test(name);

  if (isPDF) {
    await liExtractPDF(file, ta);
  } else if (isImg) {
    await liExtractImage(file, ta);
  } else {
    liSetStatus('&#9888; Unsupported file type. Please upload a PDF or image (JPG, PNG, HEIC).', 'error');
  }
}

functions.liExtractPDF:
async function liExtractPDF(file, ta) {
  liSetStatus('&#128196; Reading PDF... extracting text from lab report...', 'loading');
  try {
    var arrayBuffer = await file.arrayBuffer();
    // Configure PDF.js worker
    if (window.pdfjsLib) {
      pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
      var pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
      var allText = '';
      for (var i = 1; i <= pdf.numPages; i++) {
        var page = await pdf.getPage(i);
        var content = await page.getTextContent();
        var pageText = content.items.map(function(item) { return item.str; }).join(' ');
        allText += pageText + '\n';
      }
      allText = allText.trim();
      if (allText.length < 20) {
        // PDF has no selectable text — likely scanned image PDF
        liSetStatus('&#128247; PDF appears to be a scanned image. Running OCR (this takes 20-40 seconds)...', 'loading');
        await liOCRScannedPDF(file, ta, pdf);
        return;
      }
      ta.value = allText;
      liSetStatus('&#10003; PDF text extracted successfully — ' + allText.length + ' characters from ' + pdf.numPages + ' page(s). Review below and click Interpret.', 'success');
    } else {
      liSetStatus('&#9888; PDF library not loaded. Please paste the lab values manually.', 'error');
    }
  } catch(e) {
    liSetStatus('&#9888; Could not read PDF: ' + (e.message || 'unknown error') + '. Try taking a photo instead.', 'error');
  }
}

functions.liOCRScannedPDF:
async function liOCRScannedPDF(file, ta, pdf) {
  // For scanned PDFs, render first page as canvas and OCR it
  try {
    var page = await pdf.getPage(1);
    var scale = 2.0;
    var viewport = page.getViewport({ scale: scale });
    var canvas = document.createElement('canvas');
    canvas.width = viewport.width;
    canvas.height = viewport.height;
    var ctx = canvas.getContext('2d');
    await page.render({ canvasContext: ctx, viewport: viewport }).promise;
    var blob = await new Promise(function(res) { canvas.toBlob(res, 'image/jpeg', 0.95); });
    await liRunOCR(blob, ta, 'Scanned PDF (page 1)');
  } catch(e) {
    liSetStatus('&#9888; Could not OCR scanned PDF: ' + (e.message||'error') + '. Please take a clear photo of your report instead.', 'error');
  }
}

functions.liExtractImage:
async function liExtractImage(file, ta) {
  liSetStatus('&#128247; Reading image... running OCR to extract lab values (20-40 seconds)...', 'loading');
