}

functions.liRunOCR:
async function liRunOCR(fileOrBlob, ta, sourceName) {
  try {
    if (!window.Tesseract) {
      liSetStatus('&#9888; OCR library not loaded yet. Please wait a moment and try again.', 'error');
      return;
    }
    var worker = await Tesseract.createWorker('eng', 1, {
      logger: function(m) {
        if (m.status === 'recognizing text') {
          var pct = Math.round((m.progress || 0) * 100);
          liSetStatus('&#128247; OCR in progress: ' + pct + '%...', 'loading');
        }
      }
    });
    var result = await worker.recognize(fileOrBlob);
    await worker.terminate();
    var text = result.data.text.trim();
    if (!text || text.length < 10) {
      liSetStatus('&#9888; OCR could not read clear text from the image. Tips: ensure good lighting, hold phone steady, crop tightly to the lab values section.', 'error');
      return;
    }
    ta.value = text;
    liSetStatus('&#10003; OCR complete from ' + sourceName + ' — ' + text.length + ' characters extracted. Review text below (correct any obvious errors) then click Interpret.', 'success');
  } catch(e) {
    liSetStatus('&#9888; OCR failed: ' + (e.message||'error') + '. Please paste the lab values manually.', 'error');
  }
}
