  };

  // ── Ahara loader ──
  window._loadAharaData = function(){
    if(_loaded.ahara) return;
    var el = document.getElementById('ahara-rasa-cards');
    if(!el) return;
    fetch(GH + 'ahara.json')
      .then(function(r){ return r.json(); })
      .then(function(data){
        AHARA_DATA = data; _loaded.ahara = true;
        var cols=['#166534','#c0392b','#0369a1','#b45309','#4a7c59','#7d5a7e'];
        var bgs=['#dcfce7','#fdf0ef','#dbeafe','#fff7ed','#e8f5ee','#f5eef5'];
        el.innerHTML = data.map(function(r,i){ return '<div class="card open" style="border-left:4px solid '+cols[i]+';margin-bottom:10px">'
          +'<div class="card-hd"><div class="card-tt">'+r.rasa+'</div><div class="cbg" style="background:'+bgs[i]+';color:'+cols[i]+'">'+r.tam+'</div><div class="cbg" style="background:#f3f4f6;color:#374151;font-size:10px">'+r.ele+'</div></div>'
          +'<div class="card-bd" style="max-height:none;padding:12px 14px 14px">'
          +'<div class="tbl-scroll"><table class="ptbl"><thead><tr><th>Dosha Effect</th><th>Primary Action</th><th>Examples</th><th>Excess Effects</th></tr></thead>'
          +'<tbody><tr><td><b>'+r.dosha+'</b></td><td>'+r.action+'</td><td>'+r.examples.join(', ')+'</td><td style="color:#c0392b;font-size:11px">'+r.excess+'</td></tr></tbody></table></div>'
          +'</div></div>'; }).join('');
      })
      .catch(function(e){
        if(el) el.innerHTML = '<div class="alert a-red"><span class="a-label">Load Failed</span>Could not fetch ahara.json — '+e.message+'</div>';
      });
  };

  // ── Intercept openSec to trigger lazy-loads ──
  var _origOpenSec2 = window.openSec;
  window.openSec = function(secId, btn, skipHistory, groupKey){
    if(typeof _origOpenSec2 === 'function') _origOpenSec2(secId, btn, skipHistory, groupKey);
    if(secId === 'agni_doshas') setTimeout(window._loadAgniData, 150);
    if(secId === 'siddha')      setTimeout(window._loadSiddhaData, 150);
    if(secId === 'ahara')       setTimeout(window._loadAharaData, 150);
  };
})();

(function patchHerbDrug(){
  var HDI_URL = 'https://raw.githubusercontent.com/vikyaitool-droid/ccr-data/main/data/v1/herb_drug_interactions.json';
  var _hdiData = null;
  var _hdiLoaded = false;

  function renderHDI(container, data){
    var filtered = data;
    var herb = document.getElementById('hdi-herb-filter');
    var sev  = document.getElementById('hdi-sev-filter');
    var q    = document.getElementById('hdi-search-q');
    if(herb&&herb.value) filtered = filtered.filter(function(d){return d.herb===herb.value;});
    if(sev&&sev.value)   filtered = filtered.filter(function(d){return d.severity===sev.value;});
    if(q&&q.value.trim()){
      var qv = q.value.trim().toLowerCase();
      filtered = filtered.filter(function(d){return (d.herb+d.drug+d.effect+d.mechanism).toLowerCase().includes(qv);});
    }
    var sevColors = {major:'#c0392b',moderate:'#b45309',minor:'#0369a1'};
    var sevBg = {major:'#fdf0ef',moderate:'#fff7ed',minor:'#e0f2fe'};
    container.innerHTML = filtered.length===0?'<div style="text-align:center;padding:40px;color:var(--mu)">No interactions found for this filter.</div>'
    : filtered.map(function(d){
      var sc = sevColors[d.severity]||'#374151';
      var sb = sevBg[d.severity]||'#f3f4f6';
      return `<div class="card" onclick="this.classList.toggle('open')" style="margin-bottom:8px;border-left:4px solid ${sc}">
        <div class="card-hd">
          <div class="card-tt">${d.herb} + ${d.drug}<div style="font-size:10px;color:var(--mu);font-weight:500;margin-top:1px">${d.drugExamples?d.drugExamples.slice(0,3).join(', '):''}</div></div>
          <div class="cbg" style="background:${sb};color:${sc};text-transform:uppercase">${d.severity}</div>
          <div class="tog">+</div>
        </div>
        <div class="card-bd"><table class="ptbl"><thead><tr><th>Mechanism</th><th>Effect</th></tr></thead>
        <tbody><tr><td>${d.mechanism}</td><td>${d.effect}</td></tr></tbody></table>
        <div class="alert ${d.severity==='major'?'a-red':d.severity==='moderate'?'a-warn':'a-info'}" style="margin-top:8px"><span class="a-label">Management</span>${d.management}</div>
        ${d.references&&d.references.length?'<div class="ref-box">'+d.references.join(' · ')+'</div>':''}</div>
      </div>`;
    }).join('');
  }

  function buildHDIHerbs(data){
    var herbs = [];
    data.forEach(function(d){ if(!herbs.includes(d.herb)) herbs.push(d.herb); });
    return herbs.sort();
  }

  window._loadHDI = function(){
    var sv = document.getElementById('sv-herbdrug');
    if(!sv) return;
    var ca = sv.querySelector('.ca,.tab-index') || sv;
    if(_hdiLoaded && _hdiData){
      var grid = document.getElementById('hdi-grid');
      if(grid) renderHDI(grid, _hdiData);
      return;
    }
    // Build UI
    ca.innerHTML = `<div style="padding:14px">
      <div class="alert a-info" style="margin-bottom:12px"><span class="a-label">Clinical Herb-Drug Interaction Database</span>108 interactions · Evidence-based · Loaded from cloud repository</div>
      <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px">
        <input id="hdi-search-q" type="text" placeholder="🔍 Search herb, drug, or effect…" style="flex:1;min-width:180px;background:var(--sand);border:1.5px solid var(--bdr);border-radius:8px;padding:7px 11px;font-family:'DM Sans',inherit;font-size:13px;color:var(--tx);outline:none"/>
        <select id="hdi-herb-filter" style="background:var(--sand);border:1.5px solid var(--bdr);border-radius:8px;padding:7px 11px;font-family:'DM Sans',inherit;font-size:13px;color:var(--tx);outline:none"><option value="">All Herbs</option></select>
        <select id="hdi-sev-filter" style="background:var(--sand);border:1.5px solid var(--bdr);border-radius:8px;padding:7px 11px;font-family:'DM Sans',inherit;font-size:13px;color:var(--tx);outline:none">
          <option value="">All Severity</option><option value="major">🔴 Major</option><option value="moderate">🟡 Moderate</option><option value="minor">🔵 Minor</option>
        </select>
      </div>
      <div id="hdi-grid" style="display:flex;flex-direction:column;gap:6px"><div style="text-align:center;padding:40px;color:var(--mu)">⏳ Loading interaction database…</div></div>
    </div>`;
    fetch(HDI_URL)
      .then(function(r){ return r.json(); })
      .then(function(data){
        _hdiData = data; _hdiLoaded = true;
        var sel = document.getElementById('hdi-herb-filter');
        if(sel){ buildHDIHerbs(data).forEach(function(h){ var o=document.createElement('option'); o.value=h; o.textContent=h; sel.appendChild(o); }); }
        ['hdi-search-q','hdi-herb-filter','hdi-sev-filter'].forEach(function(id){
          var el = document.getElementById(id);
          if(el) el.addEventListener('input', function(){ renderHDI(document.getElementById('hdi-grid'), _hdiData); });
        });
        renderHDI(document.getElementById('hdi-grid'), _hdiData);
      })
      .catch(function(e){
        var grid = document.getElementById('hdi-grid');
        if(grid) grid.innerHTML = '<div class="alert a-red"><span class="a-label">Load Failed</span>Could not fetch interaction database from GitHub. Check your connection and try again.<br><small>'+e.message+'</small></div>';
      });
  };

  // Intercept openSec to trigger HDI load
  var _origOpenSec = window.openSec;
  window.openSec = function(secId, btn, skipHistory, groupKey){
    if(typeof _origOpenSec === 'function') _origOpenSec(secId, btn, skipHistory, groupKey);
    if(secId === 'herbdrug'){ setTimeout(window._loadHDI, 200); }
  };
})();
